export const FACTS: Fact[] = [
  { country: "cz", year: 1930, category: "Culture", text: "V Brně byla dokončena vila Tugendhat, kterou navrhl Mies van der Rohe se zářivou onyxovou stěnou a okny od podlahy ke stropu, jež se dala zcela spustit do podlahy. Stala se jedním z nejčistších projevů funkcionalistické architektury na světě." },
  { country: "cz", year: 1930, category: "Politics", text: "Osmdesátiletý zakládající prezident Tomáš Garrigue Masaryk, uctívaný jako filozof a státník, který republiku vybudoval, stál v čele jediné tehdy stabilní parlamentní demokracie ve střední Evropě." },
  { country: "cz", year: 1931, category: "Science & tech", text: "Polarografie, elektrochemická analytická metoda, kterou vynalezl chemik Jaroslav Heyrovský pomocí kapkové rtuťové elektrody, se šířila do laboratoří po celém světě a jednou mu měla vynést Nobelovu cenu." },
  { country: "cz", year: 1932, category: "People", text: "Tomáš Baťa, obuvnický magnát a starosta Zlína, jehož továrenské impérium bylo největší svého druhu na světě, zahynul ve svých šestapadesáti letech, když se jeho letoun Junkers krátce po startu zřítil v husté mlze." },
  { country: "cz", year: 1932, category: "Culture", text: "V únoru se narodil režisér Miloš Forman, budoucí tvůrce filmů „Přelet nad kukaččím hnízdem“ a „Amadeus“, a to v zemi, jejíž vlastní kinematografie teprve hledala svůj hlas." },
  { country: "cz", year: 1933, category: "Culture", text: "Film Gustava Machatého „Extase“, v němž osmnáctiletá Hedy Kieslerová běží s obnaženou hrudí lesem a který přinesl do té doby nevídané zobrazení orgasmu, měl premiéru v Praze a pohoršil diváky po celém světě." },
  { country: "cz", year: 1933, category: "Everyday life", text: "Na dně velké hospodářské krize vyvrcholila v únoru nezaměstnanost na zhruba 920 000 lidech, což přineslo všudypřítomné propouštění a nouzi do průmyslových měst." },
  { country: "cz", year: 1933, category: "Sport", text: "Na mistrovství světa v ledním hokeji konaném v Praze získal domácí tým bronz a byl korunován mistrem Evropy, čímž rozdmýchal národní vášeň pro tento sport, která už nikdy nevyhasla." },
  { country: "cz", year: 1933, category: "Politics", text: "Nástup Adolfa Hitlera k moci za hranicemi vyvolal v zemi vlnu obav a její třímilionová německá menšina podél hranice se stávala rostoucím zdrojem úzkosti." },
  { country: "cz", year: 1934, category: "Sport", text: "Národní fotbalový tým vedený legendárním brankářem a kapitánem Františkem Pláničkou postoupil do finále mistrovství světa v Římě, kde po dlouho vedoucím skóre prohrál v prodloužení 1:2 s Itálií." },
  { country: "cz", year: 1934, category: "Science & tech", text: "Škoda představila dostupný model 418 Popular postavený na inovativním páteřovém rámu, který přiblížil motorismus většímu počtu rodin a pomohl firmě stoupat na špici trhu." },
  { country: "cz", year: 1934, category: "Culture", text: "Komické duo Jiří Voskovec a Jan Werich z pražského avantgardního Osvobozeného divadla přeneslo svůj satirický vtip na plátno v úspěšné komedii „Hej-Rup!“." },
  { country: "cz", year: 1935, category: "Politics", text: "V parlamentních volbách získala Sudetoněmecká strana Konrada Henleina, tajně financovaná z Berlína, nejvyšší podíl hlasů ve výši 15,2 procenta, čímž posbírala zhruba dvě třetiny hlasů etnických Němců." },
  { country: "cz", year: 1935, category: "Politics", text: "Churavý Masaryk se v prosinci vzdal prezidentského úřadu a vystřídal ho jeho dlouholetý ministr zahraničí Edvard Beneš, tvůrce systému západních spojenectví republiky." },
  { country: "cz", year: 1935, category: "Politics", text: "Se Sovětským svazem byla podepsána smlouva o vzájemné pomoci, její podmínky však sovětskou pomoc podmiňovaly tím, že na obranu země nejdříve vystoupí Francie." },
  { country: "cz", year: 1936, category: "Culture", text: "Karel Čapek vydal „Válku s mloky“, drásavou satirickou alegorii fašismu a lidské chamtivosti, která upevnila jeho postavení spisovatele nominovaného na Nobelovu cenu a muže, jenž světu daroval slovo „robot“." },
  { country: "cz", year: 1936, category: "People", text: "Václav Havel, budoucí disidentský dramatik, který se měl stát prvním postkomunistickým prezidentem země, se narodil 5. října v Praze do zámožné rodiny." },
  { country: "cz", year: 1937, category: "Culture", text: "Hugo Haas natočil filmovou verzi Čapkovy protifašistické hry „Bílá nemoc“, zatímco snímek Voskovce a Wericha „Svět patří nám“ mířil proti diktatuře; oba filmy nacisté brzy zakázali." },
  { country: "cz", year: 1937, category: "People", text: "Tomáš Garrigue Masaryk, milovaný „prezident osvoboditel“, který ztělesňoval mladou demokracii, zemřel v září ve věku sedmaosmdesáti let a truchlil pro něj celý národ." },
  { country: "cz", year: 1938, category: "Sport", text: "Pražský stadion na Štvanici hostil v únoru mistrovství světa v ledním hokeji, kde domácí mužstvo porazilo Německo 3:0 a před desetitisíci fanoušků získalo bronz." },
  { country: "cz", year: 1938, category: "Upheaval", text: "Dne 23. září povolal výnos o všeobecné mobilizaci armádu, aby obsadila moderní pohraniční opevnění, a během jediného dne nastoupilo na obranu hranic asi milion mužů." },
  { country: "cz", year: 1938, category: "Upheaval", text: "V časných ranních hodinách 30. září podepsali Hitler, Chamberlain, Mussolini a Daladier Mnichovskou dohodu, jíž předali sudetské pohraničí Německu, aniž byl přítomen jediný zástupce zrazené země." },
  { country: "cz", year: 1938, category: "People", text: "Karel Čapek, který odmítl odejít do exilu, ačkoli ho gestapo označilo za „veřejného nepřítele číslo dvě“, zemřel na Boží hod vánoční na zápal plic, zlomený rozkouskováním své vlasti." },
  { country: "cz", year: 1939, category: "Upheaval", text: "V noci ze 14. na 15. března starý prezident Emil Hácha, vyhrožovaný bombardováním Prahy, zkolaboval a poté v Berlíně podepsal vzdání se nezávislosti své země, zatímco německé jednotky překračovaly hranice." },
  { country: "cz", year: 1939, category: "Upheaval", text: "Dne 16. března vyhlásil Hitler z Pražského hradu Protektorát Čechy a Morava, čímž české země degradoval na bezmocnou součást Říše a uhasil dvě desetiletí demokracie." },
  { country: "cz", year: 1940, category: "People", text: "Český stíhací eso Josef František, létající s polskou 303. perutí nad jižní Anglií, sestřelil za pouhé čtyři týdny sedmnáct německých letadel a stal se nejúspěšnějším spojeneckým pilotem bitvy o Británii, jenže v říjnu zahynul při havárii." },
  { country: "cz", year: 1940, category: "Upheaval", text: "Letci v exilu sestavili v červenci v Duxfordu 310. peruť a během jediného měsíce výcviku se vrhli do bitvy o Británii v rámci tzv. duxfordského Velkého křídla, kde si připsali desítky nepřátelských letadel." },
  { country: "cz", year: 1940, category: "Culture", text: "Okupanti zabavili zářící filmová studia na Barrandově u Prahy a proměnili je v zázemí pro Goebbelsovu propagandistickou mašinerii; mezi snímky natočenými toho roku byl i nechvalně známý antisemitský film Žid Süss." },
  { country: "cz", year: 1940, category: "Everyday life", text: "Při stále přísnějším přídělovém systému stáli obyvatelé měst hodiny ve frontách na jediný bochník chleba či kousíček masa, zatímco židovští obyvatelé měli zakázán vstup do restaurací a kin a nakupovat směli jen jednu hodinu denně." },
  { country: "cz", year: 1941, category: "Politics", text: "Reinhard Heydrich nastoupil 27. září jako zastupující říšský protektor, okamžitě vyhlásil stanné právo a nechal zatknout premiéra Aloise Eliáše, který byl pro své tajné napojení na odboj rychle odsouzen k smrti." },
  { country: "cz", year: 1941, category: "Upheaval", text: "Dne 24. listopadu dorazil do pevnostního města Terezín první transport 342 židovských mužů, čímž bylo otevřeno ghetto, jímž prošlo na 140 000 lidí a z něhož byly desetitisíce poslány dál do vyhlazovacích táborů." },
  { country: "cz", year: 1941, category: "People", text: "Václav Klaus, budoucí ekonom, který se měl stát prvním premiérem samostatného Česka a později jeho prezidentem, se narodil 19. června za nacistické okupace v pražské čtvrti Vinohrady." },
  { country: "cz", year: 1942, category: "Upheaval", text: "Dne 27. května přepadli parašutisté Jozef Gabčík a Jan Kubiš v Praze Heydrichův otevřený mercedes a smrtelně zranili říšského protektora, který svým zraněním o osm dní později podlehl." },
  { country: "cz", year: 1942, category: "Upheaval", text: "V brutální odvetě byla 10. června srovnána se zemí obec Lidice, její muži byli postříleni a ženy s dětmi odvlečeny; o dva týdny později následovalo zničení osady Ležáky." },
  { country: "cz", year: 1943, category: "Culture", text: "Děti vězněné v terezínském ghettu nacvičovaly a desítkykrát provedly dětskou operu Brundibár od Hanse Krásy, jejíž příběh o poraženém násilníkovi skýtal prchavou naději uprostřed nekonečných deportací do Osvětimi." },
  { country: "cz", year: 1944, category: "Culture", text: "SS nastrojila pro delegaci Červeného kříže, jež přijela 23. června, „zkrášlený“ Terezín, doplněný čerstvými nátěry, fotbalovým zápasem a inscenovaným představením Brundibára, a poté tento podvod natočila do propagandistického filmu, než většinu účinkujících poslala na smrt." },
  { country: "cz", year: 1945, category: "Upheaval", text: "Dne 5. května vypuklo Pražské povstání, při němž bylo po celém městě postaveno přes dva tisíce barikád, a po dnech urputných pouličních bojů byla 9. května hlavní město osvobozeno příchodem Rudé armády." },
  { country: "cz", year: 1945, category: "Politics", text: "Prezident Edvard Beneš se 16. května za jásotu davů vrátil do Prahy jako jediný východoevropský exilový vůdce, jemuž bylo dovoleno se po válce vrátit a ujmout se svého úřadu." },
  { country: "cz", year: 1945, category: "Politics", text: "Prezidentskými dekrety z 24. října byly jedním rázem znárodněny doly, banky, pojišťovny a velké průmyslové podniky, čímž se pod státní kontrolu dostaly téměř dvě třetiny průmyslu." },
  { country: "cz", year: 1946, category: "Politics", text: "Ve svobodných volbách 26. května získala Komunistická strana 38 procent hlasů, více než kdy předtím jakákoli strana, a její vůdce Klement Gottwald se v červenci stal premiérem koalice Národní fronty." },
  { country: "cz", year: 1946, category: "Everyday life", text: "Státem řízený odsun zhruba tří milionů etnických Němců, posvěcený v Postupimi, vylidnil pohraničí a následovala vlna dosídlenců, kteří se stěhovali do opuštěných sudetských statků a měst." },
  { country: "cz", year: 1947, category: "Politics", text: "Ministr zahraničí Jan Masaryk a další představitelé se chtěli zapojit do amerického Marshallova plánu, Stalin si je však předvolal do Moskvy a 10. července donutil vládu pomoc odmítnout." },
  { country: "cz", year: 1947, category: "Upheaval", text: "Kruté sucho táhnoucí se od dubna do října sežehlo obilnou sklizeň a zemi tak ponechalo závislou na politicky motivovaných dodávkách obilí od Sovětského svazu, který sám sevřel hladomor." },
  { country: "cz", year: 1947, category: "Culture", text: "Jiří Trnka uvedl svůj první celovečerní loutkový film Špalíček, lyrický cyklus venkovských zvyků a ročních období, který získal zlatou medaili v Benátkách a proslavil jeho jméno v animaci." },
  { country: "cz", year: 1947, category: "Sport", text: "Národní hokejový tým získal v únoru na domácím ledě v Praze svůj první titul mistrů světa a přihlásil se o slovo jako dominantní síla evropského hokeje." },
  { country: "cz", year: 1948, category: "Politics", text: "Koncem února se komunisté chopili plné kontroly nad státem a 25. února přijal zahnaný prezident Beneš vládu podle jejich podmínek, čímž začaly čtyři desetiletí vlády jedné strany." },
  { country: "cz", year: 1948, category: "People", text: "Dne 10. března byl pod okny svého bytu nalezen mrtvý ministr zahraničí Jan Masaryk, syn zakladatele republiky; jeho smrt byla úředně označena za sebevraždu, dlouho ji však zastiňovalo podezření z vraždy." },
  { country: "cz", year: 1948, category: "Sport", text: "Na olympijských hrách v Londýně získal Emil Zátopek zlato v běhu na 10 000 metrů, kde o kolo předběhl všechny soupeře až na dva, a stříbro na 5 000 metrů, pouhých pár týdnů poté, co delší trať běžel teprve podruhé v životě." },
  { country: "cz", year: 1948, category: "Everyday life", text: "Na XI. všesokolském sletu v Praze toho léta předvedlo zhruba 150 000 dospělých hromadná tělocvičná vystoupení před davy a mnozí účastníci proměnili průvod v otevřený protest proti novému režimu, za což byly tisíce z nich později pronásledovány." },
  { country: "cz", year: 1949, category: "Everyday life", text: "Obuvnický gigant Baťa, již znárodněný, se dočkal toho, že jeho rodný Zlín byl přejmenován na Gottwaldov podle komunistického prezidenta, čímž zmizelo jméno zakladatele z mapy „města postaveného na botách“." },
  { country: "cz", year: 1949, category: "Sport", text: "Poté co předchozí listopad přišel o šest hráčů, jejichž letadlo zmizelo nad Lamanšským průlivem, sebral truchlící národní hokejový tým síly a v únoru vyhrál mistrovství světa ve Stockholmu." },
  { country: "cz", year: 1950, category: "Politics", text: "Dne 27. června byla demokratická politička a právnička Milada Horáková oběšena v pražské pankrácké věznici po zinscenovaném, rozhlasem vysílaném procesu, čímž se stala jedinou ženou popravenou komunistickým režimem z politických důvodů, a to navzdory protestům Alberta Einsteina, Winstona Churchilla a Eleanor Rooseveltové." },
  { country: "cz", year: 1950, category: "Sport", text: "V březnu tajná policie zatkla hráče mistrovského národního hokejového týmu a po vykonstruovaném procesu poslala hvězdy jako brankáře Bohumila Modrého do uranových táborů na Jáchymovsku, kde ozáření později několik z nich připravilo o život." },
  { country: "cz", year: 1951, category: "Upheaval", text: "Úřady zahájily „akci Kulak“, při níž násilně vystěhovaly zhruba 4 000 zámožných sedláckých rodin z jejich půdy a domovů v rámci násilného tažení za zahnání rolníků do jednotných zemědělských družstev." },
  { country: "cz", year: 1952, category: "Sport", text: "Na olympijských hrách v Helsinkách dokázal vojenský běžec Emil Zátopek něco, co se už nikdy neopakovalo: získal zlato na 5 000 metrů, 10 000 metrů a z rozmaru i v maratonu, který běžel vůbec poprvé v životě." },
  { country: "cz", year: 1952, category: "Politics", text: "V antisemitském Slánského procesu bylo čtrnáct vysokých komunistů, z toho jedenáct židovského původu, odsouzeno za smyšlené „sionistické spiknutí“ a 3. prosince bylo jedenáct z nich oběšeno na Pankráci, mezi nimi i bývalý generální tajemník strany Rudolf Slánský." },
  { country: "cz", year: 1953, category: "Everyday life", text: "Brutální měnová reforma z 1. června vymazala hotovostní úspory v poměru padesáti starých korun za jednu novou, ze dne na den zrušila státní dluhy a ukončila přídělový systém, který udržoval potraviny levné." },
  { country: "cz", year: 1953, category: "Upheaval", text: "Když byla měnová reforma vyhlášena, povstaly v Plzni tisíce lidí, většinou dělníků ze Škodovky, stavěly barikády a strhávaly komunistické symboly v dělnické vzpouře, která předcházela většímu východoněmeckému povstání o dva týdny později." },
  { country: "cz", year: 1953, category: "Politics", text: "Tvrdě zaměřený prezident Klement Gottwald zemřel 14. března, pouhých pár dní po návratu ze Stalinova pohřbu v Moskvě, a vystřídal ho bývalý odborový předák Antonín Zápotocký." },
  { country: "cz", year: 1953, category: "Culture", text: "Dne 1. května odvysílalo Studio Praha první televizní přenos v zemi, který se otevřel krátkým výstupem herce Františka Filipovského a byl černobíle vyslán k pouhé hrstce přijímačů." },
  { country: "cz", year: 1954, category: "Culture", text: "Režisér Otakar Vávra uvedl film „Jan Hus“, první díl své okázalé husitské revoluční trilogie a do té doby nejdražší domácí filmový projekt, který vyprávěl o upálení středověkého reformátora na hranici v roce 1415." },
  { country: "cz", year: 1955, category: "Everyday life", text: "Dne 1. května byl na Letné nad Prahou odhalen 15,5 metru vysoký žulový kolos Stalina vedoucího dělníky, největší socha tohoto diktátora na světě, přičemž její sochař Otakar Švec si pár dní před slavnostním odhalením vzal život." },
  { country: "cz", year: 1955, category: "Sport", text: "První spartakiáda, hromadné vystoupení synchronizované gymnastiky s obrovským počtem cvičenců, zaplnila 23. června rozlehlý pražský Strahovský stadion a přetavila tradice zakázaného sokolského hnutí v komunistickou podívanou." },
  { country: "cz", year: 1955, category: "Politics", text: "Po smrti Stalina a Gottwalda osvobodila lednová amnestie vězněné reprezentační hokejisty, byť mnozí vyšli z uranových dolů se zničeným zdravím." },
  { country: "cz", year: 1956, category: "Science & tech", text: "Firma Tatra představila aerodynamickou Tatru 603 s motorem vzadu, luxusní sedan se vzduchem chlazeným osmiválcem, vyhrazený téměř výhradně pro vysoké stranické funkcionáře a šéfy továren." },
  { country: "cz", year: 1956, category: "People", text: "Budoucí tenisová šampionka Martina Navrátilová se narodila 18. října v Praze, zhruba dvě desetiletí předtím, než emigrovala do Spojených států a přepsala wimbledonské rekordy." },
  { country: "cz", year: 1956, category: "Culture", text: "Otakar Vávra dovršil svůj husitský epos filmem „Jan Žižka“, v němž v souladu s oficiální ideologií oslavil jednookého středověkého vojevůdce jako předchůdce revolučního boje." },
  { country: "cz", year: 1957, category: "Culture", text: "První film animátora Zdeňka Milera o Krtkovi, „Jak krtek ke kalhotkám přišel“, získal stříbrného lva na filmovém festivalu v Benátkách a dal vzniknout milované, téměř beze slov němé kreslené postavičce známé po celém světě." },
  { country: "cz", year: 1957, category: "Politics", text: "Prezident Antonín Zápotocký zemřel 13. listopadu na infarkt a stalinistický šéf strany Antonín Novotný se zmocnil i prezidentského úřadu, čímž oba nejvyšší posty soustředil do svých rukou." },
  { country: "cz", year: 1957, category: "Sport", text: "Emil Zátopek, „česká lokomotiva“, ukončil závodní kariéru a zanechal po sobě čtyři olympijské zlaté medaile a dlouhou řadu světových rekordů v dlouhých tratích." },
  { country: "cz", year: 1958, category: "Culture", text: "Na bruselském Expo 58 byl československý pavilon vyhlášen nejlepším na celé výstavě a jeho oslnivá Laterna magika, spojující živé herce s promítaným filmem pod vedením Alfréda Radoka a scénografa Josefa Svobody, dala světu poprvé okusit multimediální divadlo." },
  { country: "cz", year: 1958, category: "People", text: "Mladý scenárista jménem Miloš Forman se na podívané Laterny magiky v Bruselu vyučil řemeslu léta předtím, než se stal oscarovým filmovým režisérem." },
  { country: "cz", year: 1959, category: "Science & tech", text: "V Praze začal chemik Otto Wichterle experimentálně nasazovat pacientům první měkké hydrogelové kontaktní čočky na světě, průlom, který brzy zdokonalil jejich odléváním na odstředivém přístroji sestaveném zčásti ze stavebnice jeho dětí." },
  { country: "cz", year: 1959, category: "Culture", text: "Triumf Laterny magiky v zahraničí vedl v květnu k založení stálého multimediálního divadelního souboru v Praze, čímž se tato umělecká forma upevnila jako národní kulturní vývozní artikl." },
  { country: "cz", year: 1960, category: "Politics", text: "Nová marxisticko-leninská ústava vyhlášená 11. července přejmenovala zemi na Československou socialistickou republiku a hrdě ji prohlásila za první stát po Sovětském svazu, který „dovršil socialismus“." },
  { country: "cz", year: 1960, category: "Science & tech", text: "Časopis Nature otiskl článek „Hydrofilní gely pro biologické použití“ od chemiků Otty Wichterleho a Drahoslava Líma, který položil vědecké základy měkkých kontaktních čoček." },
  { country: "cz", year: 1960, category: "People", text: "Budoucí světová tenisová jednička Ivan Lendl, který měl v 80. letech ovládnout mužský tenis, se toho roku narodil 7. března v Ostravě." },
  { country: "cz", year: 1961, category: "Science & tech", text: "Na Štědrý den odpoledne odlil Otto Wichterle první čtyři měkké hydrogelové kontaktní čočky na podomácku sestaveném přístroji z dětské stavebnice Merkur svých synů a jízdního dynama." },
  { country: "cz", year: 1961, category: "Everyday life", text: "Přehnaně ambiciózní třetí pětiletka spuštěná toho roku se brzy ukázala jako beznadějně nereálná a předznamenala nedostatek spotřebního zboží a dlouhé fronty na základní výrobky." },
  { country: "cz", year: 1962, category: "Sport", text: "Národní fotbalový tým postoupil do finále mistrovství světa v Santiagu, kde po brzkém vedení gólem Josefa Masopusta prohrál 1:3 s Brazílií a skončil druhý." },
  { country: "cz", year: 1963, category: "Everyday life", text: "Národní důchod toho roku dokonce klesl, když plánovači opustili hroutící se pětiletku ve prospěch ročních cílů, a průmyslový růst patřil k nejnižším ve východní Evropě." },
  { country: "cz", year: 1963, category: "Sport", text: "Na mistrovství světa v ledním hokeji ve Stockholmu porazil národní tým Švédsko 3:2 a získal bronzovou medaili." },
  { country: "cz", year: 1964, category: "Everyday life", text: "Škoda 1000 MB s motorem vzadu, pojmenovaná podle svého domovského města Mladá Boleslav, debutovala v dubnu jako první sériově vyráběné auto v zemi se samonosnou karoserií." },
  { country: "cz", year: 1964, category: "Sport", text: "Na zimních olympijských hrách v Innsbrucku skončil hokejový tým s bronzem za stříbrným Švédskem a zlatým Sovětským svazem." },
  { country: "cz", year: 1965, category: "Culture", text: "Válečné drama „Obchod na korze“ režisérů Jána Kadára a Elmara Klose získalo Oscara za nejlepší cizojazyčný film, první Oscar pro zemi." },
  { country: "cz", year: 1965, category: "Culture", text: "Československá televize odvysílala 2. ledna první díl „Večerníčku“, oblíbeného večerního pořadu pro děti, který brzy přijal svůj nehynoucí obraz chlapečka s papírovou čepicí na houpacím koníku přejícího divákům dobrý večer." },
  { country: "cz", year: 1966, category: "Culture", text: "Anarchická feministická komedie Věry Chytilové „Sedmikrásky“ byla doma zakázána, zčásti kvůli scénám okázalého plýtvání jídlem v době nedostatku spotřebního zboží, a její režisérka měla na léta zákaz natáčet." },
  { country: "cz", year: 1966, category: "Everyday life", text: "Technologie panelové výstavby rychle pokročila a na okrajích měst vyrůstaly obří obytné bloky o stovkách bytů, stále častěji zjemněné obchody, školami a poliklinikami." },
  { country: "cz", year: 1967, category: "Culture", text: "Na IV. sjezdu spisovatelů v červnu otevřeně napadli Milan Kundera, Ludvík Vaculík, Pavel Kohout a Václav Havel cenzuru a vládu strany, což je výbuch často považovaný za předehru pražského jara." },
  { country: "cz", year: 1967, category: "Culture", text: "Film Jiřího Menzela o dospívání „Ostře sledované vlaky“, natočený podle novely Bohumila Hrabala, byl uveden v zahraničí a získal Oscara za nejlepší cizojazyčný film." },
  { country: "cz", year: 1968, category: "Politics", text: "Zvolení reformátora Alexandra Dubčeka prvním tajemníkem Komunistické strany dne 5. ledna odstartovalo pražské jaro a jeho příslib „socialismu s lidskou tváří“." },
  { country: "cz", year: 1968, category: "Culture", text: "Na sedmdesát intelektuálů a umělců podepsalo manifest „Dva tisíce slov“, který sepsal spisovatel Ludvík Vaculík a jenž byl zveřejněn 27. června s výzvou k hlubší demokratizaci." },
  { country: "cz", year: 1968, category: "Upheaval", text: "V noci z 20. na 21. srpna vtrhlo do země v rámci operace Dunaj na půl milionu vojáků Varšavské smlouvy s tisíci tanků, kteří rozdrtili reformy a zabili přes sto civilistů." },
  { country: "cz", year: 1968, category: "Culture", text: "Pár dní po vpádu tanků nahrála zpěvačka Marta Kubišová „Modlitbu pro Martu“, která se stala hymnou národního odporu, než ji režim zakázal a na dvě desetiletí jí znemožnil vystupovat." },
  { country: "cz", year: 1968, category: "Sport", text: "Na olympijských hrách v Ciudad de México získala gymnastka Věra Čáslavská čtyři zlaté a dvě stříbrné medaile a během hymny okázale sklonila a odvrátila hlavu od sovětské vlajky na tichý protest proti invazi." },
  { country: "cz", year: 1969, category: "Politics", text: "Dne 1. ledna se z unitárního státu stala federace České socialistické republiky a Slovenské socialistické republiky s novým dvoukomorovým Federálním shromážděním." },
  { country: "cz", year: 1969, category: "Upheaval", text: "Dne 16. ledna se dvacetiletý student Jan Palach upálil na Václavském náměstí na protest proti okupaci a o tři dny později zemřel; jeho pohřbu se zúčastnilo na 200 000 truchlících." },
  { country: "cz", year: 1969, category: "Sport", text: "Když národní hokejový tým v březnu na mistrovství světa ve Stockholmu dvakrát porazil Sovětský svaz, zaplnily ulice jásající davy a demonstranti vyrabovali kancelář sovětského Aeroflotu na Václavském náměstí." },
  { country: "cz", year: 1969, category: "Everyday life", text: "Do konce roku bylo po celé zemi v provozu na tři miliony televizorů, což odráželo rychlé rozšíření tohoto média během desetiletí." },
  { country: "cz", year: 1969, category: "People", text: "Olympijská běžecká legenda Emil Zátopek, který podpořil pražské jaro a podepsal Dva tisíce slov, byl zbaven vojenské hodnosti, vyloučen ze strany a poslán dřít do uranových dolů na Jáchymovsku." },
  { country: "cz", year: 1970, category: "Politics", text: "Během čistek po pražském jaru vyloučily prověrkové komise z Komunistické strany zhruba půl milionu členů a ztráta stranické legitimace tak často znamenala konec kariéry, že vyhození profesoři řídili taxíky a bývalí diplomaté pracovali jako úředníci v hotelech." },
  { country: "cz", year: 1970, category: "Politics", text: "Gustáv Husák utužil své postavení vůdce strany, nahradil reformní členy ústředního výboru zastánci tvrdé linie a po rozdrcených reformách roku 1968 zemi pevně navrátil do řad sovětského bloku." },
  { country: "cz", year: 1971, category: "Politics", text: "Na oficiálně posvěceném XIV. sjezdu strany v květnu prohlásilo vedení proces „normalizace“ za uspokojivě dokončený a parlamentní volby v listopadu poslušně potvrdily jedinou schválenou kandidátku režimu obvyklým téměř jednomyslným hlasováním." },
  { country: "cz", year: 1972, category: "Sport", text: "Dne 15. února se v hornickém městě Kladno narodila budoucí hokejová legenda, jež se měla stát jedním z nejproduktivnějších střelců bodů v historii NHL." },
  { country: "cz", year: 1972, category: "Sport", text: "Na mistrovství světa v ledním hokeji pořádaném v dubnu v Praze porazil domácí tým ve skupině dvakrát Sovětský svaz a získal zlato, čímž ukončil sovětskou sérii devíti titulů v řadě a rozpoutal jásot v ulicích." },
  { country: "cz", year: 1972, category: "Science & tech", text: "Odvážný asymetrický zavěšený most přes Dunaj v Bratislavě, korunovaný restaurací ve tvaru létajícího talíře na vrcholu jediného 85metrového pylonu, byl 26. srpna po letech výstavby slavnostně otevřen." },
  { country: "cz", year: 1973, category: "Politics", text: "Dne 11. prosince byla se Západním Německem podepsána Pražská smlouva, která prohlásila Mnichovskou dohodu z roku 1938 za neplatnou a poprvé od druhé světové války navázala mezi oběma státy plné diplomatické vztahy." },
  { country: "cz", year: 1974, category: "Everyday life", text: "Na okrajích měst vyrůstala rozlehlá panelová sídliště, nejambicióznější z nich pražské Jižní Město, které se nakonec stalo domovem zhruba 100 000 lidí a kde si rodiny cenily nového bytu navzdory zdem tak tenkým, že sousedovy televizory i hádky byly slyšet skrz." },
  { country: "cz", year: 1975, category: "Sport", text: "Dne 6. září emigroval do Spojených států osmnáctiletý tenisový zázrak, který právě prohrál semifinále US Open s Chris Evertovou, a požádal o politický azyl, načež jej úřady zbavily občanství." },
  { country: "cz", year: 1976, category: "Sport", text: "Dne 20. června v Bělehradě porazil národní fotbalový tým Západní Německo v penaltovém rozstřelu a získal mistrovství Evropy, přičemž rozhodující kop byl drzým lobem doprostřed branky, který se od té doby napodobuje jako „panenka“." },
  { country: "cz", year: 1976, category: "Sport", text: "Hokejový tým získal v Katovicích svůj čtvrtý titul mistrů světa, když neporažen prošel všemi devíti zápasy turnaje." },
  { country: "cz", year: 1976, category: "Culture", text: "Poté co jarní zásah pochytal desítky hudebníků, byli v září souzeni čtyři členové zakázané undergroundové rockové kapely The Plastic People of the Universe a uvězněni za „organizované výtržnictví“; tento proces pomohl podnítit sepsání slavného manifestu za lidská práva." },
  { country: "cz", year: 1976, category: "Everyday life", text: "Hranaté Škody 105 a 120 s motorem vzadu byly představeny na brněnském strojírenském veletrhu a prodávaly se za zhruba 55 000 až 58 000 korun kupcům, kteří na nárok koupit si auto často čekali roky." },
  { country: "cz", year: 1976, category: "Culture", text: "Režisérce Věře Chytilové, která měla od invaze roku 1968 zákaz natáčet, bylo konečně dovoleno vrátit se za kameru a natočit Hru o jablko, byť nejdříve musela napsat přímo prezidentu Husákovi a dovolávat se práva na práci." },
  { country: "cz", year: 1977, category: "Politics", text: "Dne 6. ledna se objevila deklarace za lidská práva Charta 77 s 242 zakládajícími signatáři, kteří vyzývali vládu, aby ctila helsinská ujednání, a její kurýři, mezi nimi Václav Havel, byli zadrženi při pokusu doručit ji Federálnímu shromáždění." },
  { country: "cz", year: 1977, category: "Culture", text: "V rychlé, státem zinscenované odpovědi se tisíce předních umělců a spisovatelů sešly v Národním divadle, aby podpořily „Antichartu“, mezi jejímiž jmény byl i slavný zpěvák Karel Gott, ačkoli někteří později tvrdili, že byli o tom, co podepisují, uvedeni v omyl." },
  { country: "cz", year: 1977, category: "Culture", text: "Měl premiéru oblíbený seriál Žena za pultem, postavený na každodenním životě pražské prodavačky, který upoutal pozornost vedení Komunistické strany, zčásti kvůli jedné ze svých scén." },
  { country: "cz", year: 1977, category: "People", text: "Filozof Jan Patočka, jeden ze tří původních mluvčích Charty 77, zemřel v březnu po sérii vyčerpávajících policejních výslechů a jeho pohřeb se pod přísným dohledem stal tichým aktem vzdoru." },
  { country: "cz", year: 1978, category: "Science & tech", text: "Dne 2. března odstartoval vojenský pilot na palubě Sojuzu 28, aby se spojil se stanicí Saljut 6, čímž se stal prvním člověkem ve vesmíru z jiné země než Sovětského svazu nebo Spojených států, a 10. března se vrátil na Zemi." },
  { country: "cz", year: 1978, category: "Culture", text: "Začalo se vysílat nemocniční drama Nemocnice na kraji města, které se stalo milovanou národní institucí, a jeho soubor lékařů sledovaly miliony rodin shromážděných u televize." },
  { country: "cz", year: 1978, category: "Everyday life", text: "Pro nedostatkové západní zboží, jako byly džíny, zahraniční elektronika a kvalitní káva, se občané obraceli na státní devizové prodejny Tuzex, jejichž zvláštní poukázky obchodovali na kvetoucím černém trhu šmelináři známí jako „vekslaci“." },
  { country: "cz", year: 1979, category: "Upheaval", text: "V říjnu bylo šest členů Výboru na obranu nespravedlivě stíhaných souzeno za podvracení republiky a dramatik Václav Havel byl odsouzen ke čtyřem a půl rokům vězení." },
  { country: "cz", year: 1979, category: "Everyday life", text: "Po celé desetiletí režim vyměňoval spotřebitelské pohodlí za politický klid a panelákový byt na sídlišti, rodinná škodovka a víkendová chata, kam mnozí utíkali zahradničit, se staly skromnými obzory běžného života." },
  { country: "cz", year: 1980, category: "Sport", text: "Ivan Lendl, neporažený v sedmi dvouhrách a třech čtyřhrách, dovedl národní tým k jeho prvnímu titulu v Davisově poháru vítězstvím 4:1 nad Itálií před bouřlivým domácím publikem v Praze." },
  { country: "cz", year: 1980, category: "Sport", text: "Na zimních olympijských hrách v Lake Placid byl silně favorizovaný hokejový tým šokován porážkou 3:7 od outsiderského mužstva Spojených států, které následně dosáhlo svého slavného „zázraku na ledě“." },
  { country: "cz", year: 1980, category: "Everyday life", text: "Obyčejné rodiny snášely několikaleté čekací listiny na tuzemsky vyrobenou škodovku a pak, když na ně konečně přišla řada, odevzdaly za hranatý malý sedan léta úspor." },
  { country: "cz", year: 1981, category: "Politics", text: "Režim Gustáva Husáka vstoupil do nového desetiletí vymáháním strnulé „normalizace“, vyžadoval konformitu ve veřejném životě a zároveň se snažil koupit si poslušnost mírně zlepšenou životní úrovní." },
  { country: "cz", year: 1981, category: "Everyday life", text: "Nedostatek byl součástí každodenního života, občané běžně stáli hodiny ve frontách a improvizovali přes černý trh, aby sehnali všechno od cukru po náhradní díly." },
  { country: "cz", year: 1982, category: "Sport", text: "Na mistrovství světa v ledním hokeji ve Finsku v únoru získal národní tým stříbro poté, co prohrál rozhodující zápas 3:5 se Sovětským svazem, jenž si připsal druhý titul mistrů světa v řadě." },
  { country: "cz", year: 1982, category: "Sport", text: "Ivan Lendl, rodák z Ostravy, kraloval mužskému tenisu: vyhrál patnáct z třiadvaceti turnajů, jichž se zúčastnil, a nasázel 44 vítězných zápasů v řadě, třetí nejdelší sérii otevřené éry, než porazil Johna McEnroea a získal závěrečný turnaj sezony WCT Finals v Dallasu." },
  { country: "cz", year: 1983, category: "Culture", text: "Článek v komunistickém týdeníku Tribuna „Nová vlna se starým obsahem“ označil rock za zhoubný vliv na mládež a odstartoval zásah, který brzy připravil oblíbené kapely o jejich provozovací licence." },
  { country: "cz", year: 1983, category: "Culture", text: "Uznávaná novovlnná kapela Pražský výběr přišla o provozovací licenci a byla fakticky zakázána, oběť oficiální kampaně líčící rockovou hudbu jako cestu k pasivitě a asociálnímu chování." },
  { country: "cz", year: 1983, category: "Everyday life", text: "Občané s devizami nebo speciálně koupenými poukázkami nakupovali v prodejnách Tuzex vytoužené západní zboží, především džíny, které byly v běžných obchodech nesehnatelné." },
  { country: "cz", year: 1984, category: "Sport", text: "Národní hokejový tým získal stříbro na zimních olympijských hrách v Sarajevu poté, co v rozhodujícím zápase turnaje nedokázal vstřelit Sovětskému svazu jediný gól." },
  { country: "cz", year: 1984, category: "Culture", text: "Karel Gott, hebkohlasý zpěvák přezdívaný „zlatý hlas Prahy“, kraloval jako nejoblíbenější zpěvák země a jeho hvězdnou slávu si oblíbil režim, jehož petici Anticharta podepsal." },
  { country: "cz", year: 1985, category: "Sport", text: "Před jásajícím domácím publikem v Praze porazil národní hokejový tým Kanadu 5:3 a zajistil si šestý titul mistrů světa, čímž odsunul favorizovaný Sovětský svaz na bronz." },
  { country: "cz", year: 1985, category: "Culture", text: "Něžná komedie Jiřího Menzela „Vesničko má středisková“, sledující mírného a popleteného Otíka v semknuté venkovské komunitě, se stala milovaným hitem a vysloužila si nominaci na Oscara." },
  { country: "cz", year: 1985, category: "Everyday life", text: "Desetitisíce sladěných cvičenců zaplnily rozlehlý Strahovský stadion při hromadné gymnastické přehlídce konané jednou za pět let, spartakiádě, která uvedla nesmrtelně chytlavou popovou hymnu „Poupata“." },
  { country: "cz", year: 1985, category: "Politics", text: "Hluboko přes sto tisíc katolíků vzdorovalo režimu na pouti na Velehrad u příležitosti 1100. výročí úmrtí svatého Metoděje, vypískalo představitele moci a proměnilo náboženské shromáždění v odvážný protest." },
  { country: "cz", year: 1986, category: "Upheaval", text: "Po černobylské katastrofě úřady utajily informace a uskutečnily tradiční prvomájové oslavy, takže lidé se opalovali a pochodovali venku, zatímco nad nimi se snášel radioaktivní spad." },
  { country: "cz", year: 1986, category: "Culture", text: "Policie zatkla Karla Srpa, vedoucího nezávislé Jazzové sekce, který byl později uvězněn na šestnáct měsíců, čímž byla potrestána organizace, jejíž pašované knihy a desky se dostaly k tisícům čtenářů." },
  { country: "cz", year: 1986, category: "Sport", text: "Hvězdy v exilu Ivan Lendl a Martina Navrátilová ovládly světový tenis jako mužská a ženská jednička, ačkoli režim s emigrovavší Navrátilovou doma zacházel jako s neexistující osobou." },
  { country: "cz", year: 1987, category: "Politics", text: "Čtyřiasedmdesátiletý Gustáv Husák odstoupil z funkce šéfa Komunistické strany ve prospěch konzervativního Miloše Jakeše, přičemž se držel převážně ceremoniálního postu prezidenta." },
  { country: "cz", year: 1987, category: "Science & tech", text: "Desetiletí spalování sirnatého hnědého uhlí učinila ze severních Čech součást evropského „černého trojúhelníku“, kde kyselé deště ničily celé pásy lesů a místní trpěli dýchacími nemocemi dvojnásobně oproti celostátnímu průměru." },
  { country: "cz", year: 1988, category: "Upheaval", text: "V Bratislavě uspořádaly tisíce katolíků tichou demonstraci se svíčkami za náboženskou svobodu, kterou pořádková policie rozehnala vodními děly, ojedinělou otevřenou výzvu režimu." },
  { country: "cz", year: 1989, category: "Upheaval", text: "Během „Palachova týdne“ v lednu, připomínajícího dvacet let od upálení Jana Palacha, se pořádková policie střetla s demonstranty a zatkla stovky lidí, mezi nimi i disidentského dramatika Václava Havla." },
  { country: "cz", year: 1989, category: "Upheaval", text: "Dne 17. listopadu pořádková policie násilně rozehnala studentský pochod připomínající nacistický zásah z roku 1939, čímž zažehla pokojnou sametovou revoluci, která během několika týdnů svrhla komunistický režim." },
  { country: "cz", year: 1989, category: "Politics", text: "Půl milionu lidí zaplnilo pražské ulice a celostátní generální stávka 27. listopadu pomohla donutit Komunistickou stranu, aby se vzdala svého ústavního mocenského monopolu." },
  { country: "cz", year: 1989, category: "People", text: "Dne 29. prosince zvolilo Federální shromáždění prezidentem kdysi vězněného disidentského dramatika Václava Havla, čímž korunovalo rok, který pro něj začal za mřížemi." },
  { country: "cz", year: 1990, category: "Politics", text: "Ve dnech 8. a 9. června přišli voliči k urnám v prvních svobodných volbách po 44 letech, přičemž účast dosáhla mimořádných 96,2 procenta a hnutí Občanské fórum dosáhlo drtivého vítězství." },
  { country: "cz", year: 1990, category: "Culture", text: "Dne 18. srpna zahráli Rolling Stones více než 100 000 fanouškům na rozlehlém pražském Strahovském stadionu pod heslem „Tanky pryč, Stones sem“." },
  { country: "cz", year: 1990, category: "Politics", text: "Dne 5. července byl bývalý disidentský dramatik Václav Havel Federálním shromážděním znovu zvolen prezidentem, čímž zpečetil svou cestu z vězeňské cely do prezidentského úřadu." },
  { country: "cz", year: 1990, category: "People", text: "Budoucí dvojnásobná wimbledonská vítězka a světová tenisová dvojka Petra Kvitová se narodila 8. března ve městě Bílovec." },
  { country: "cz", year: 1990, category: "Culture", text: "Rocková kapela Lucie v čele s Robertem Kodymem vydala své debutové album a stala se jednou z nejoblíbenějších skupin své doby; hity jako „Medvídek“ a „Amerika“ utvářely zvukovou kulisu porevolučního desetiletí." },
  { country: "cz", year: 1991, category: "Upheaval", text: "Dne 27. června odešel poslední sovětský voják, čímž skončila vojenská okupace, jež začala invazí Varšavské smlouvy v roce 1968 a po 23 let zde rozmísťovala desetitisíce vojáků." },
  { country: "cz", year: 1991, category: "Politics", text: "Dne 4. října schválil parlament lustrační zákon, který bývalým spolupracovníkům tajné policie a vysokým komunistickým funkcionářům zakázal zastávat širokou škálu veřejných funkcí." },
  { country: "cz", year: 1991, category: "Everyday life", text: "Dne 28. března podepsaly vláda a Volkswagen dohodu, jíž se německý gigant stal strategickým partnerem Škodovky, čímž začala přeměna výrobce hranatého Favoritu v globální značku." },
  { country: "cz", year: 1992, category: "Everyday life", text: "Dne 20. března otevřel v pražské Vodičkově ulici první McDonald's, který přilákal odhadem 11 000 lidí, již se ve frontě dočkali první ochutnávky amerického hamburgeru." },
  { country: "cz", year: 1992, category: "Politics", text: "Pod vedením ministra financí a později premiéra Václava Klause používali občané knížky kuponů k nákupu akcií státních podniků v rámci hromadné kuponové privatizace, která veřejnosti předala vlastnictví dříve socialistického hospodářství." },
  { country: "cz", year: 1992, category: "Politics", text: "Dne 25. listopadu schválilo Federální shromáždění ústavní zákon o rozdělení země na dva státy ke konci roku, čímž zpečetilo takzvaný sametový rozvod." },
  { country: "cz", year: 1992, category: "Politics", text: "Dne 16. prosince přijala Česká národní rada novou ústavu brzy samostatné republiky, jež měla vejít v platnost první den roku 1993." },
  { country: "cz", year: 1993, category: "Politics", text: "Dne 1. ledna se země pokojně rozdělila na dva nové státy, když současně vznikly samostatná Česká republika a Slovensko v jediném zcela nekrvavém rozpadu v bývalém východním bloku." },
  { country: "cz", year: 1993, category: "Politics", text: "Dne 26. ledna byl Václav Havel zvolen prvním prezidentem nově samostatné republiky, když v prvním kole získal 109 hlasů, a úřadu se ujal 2. února." },
  { country: "cz", year: 1993, category: "Everyday life", text: "Dne 8. února byla rozdělena společná federální měna, přičemž prvními novými penězi byly staré bankovky s nalepenými kolky označujícími jejich nominální hodnotu, než bylo možné vytisknout nově navržené bankovky." },
  { country: "cz", year: 1994, category: "Culture", text: "Dne 4. února začala vysílat TV Nova jako první celostátní soukromá komerční televizní stanice v celém bývalém východním bloku a rychle si získala největší publikum v zemi." },
  { country: "cz", year: 1995, category: "Politics", text: "Dne 21. prosince se země stala prvním postkomunistickým státem, který vstoupil do OECD, což byl milník v jejím opětovném začlenění mezi západní ekonomiky." },
  { country: "cz", year: 1996, category: "Sport", text: "Dne 25. května hodil Jan Železný oštěpem 98,48 metru v německé Jeně a vytvořil světový rekord, který i o desítky let později stále platí jako jeden z nejnedotknutelnějších zápisů atletiky." },
  { country: "cz", year: 1996, category: "Sport", text: "Dne 30. června prohrál národní fotbalový tým finále mistrovství Evropy 1:2 s Německem na Wembley, poražen zlatým gólem Olivera Bierhoffa v prodloužení poté, co Patrik Berger poslal tým do vedení z penalty." },
  { country: "cz", year: 1996, category: "Sport", text: "Na letních olympijských hrách v Atlantě úspěšně obhájil Jan Železný svůj olympijský titul v hodu oštěpem a získal druhé ze svých tří olympijských zlat v řadě." },
  { country: "cz", year: 1997, category: "Upheaval", text: "Počátkem července vyvolaly katastrofální deště takzvanou „povodeň století“ na Moravě a ve Slezsku, jež zabila téměř 60 lidí, připravila přes deset tisíc o domov a zaplavila historické centrum Olomouce." },
  { country: "cz", year: 1997, category: "Culture", text: "Dne 24. března získal film Kolja režiséra Jana Svěráka, v němž jeho otec Zdeněk Svěrák hraje pražského violoncellistu, jenž nečekaně vychovává malého ruského chlapce, Oscara za nejlepší cizojazyčný film." },
  { country: "cz", year: 1998, category: "Sport", text: "Dne 22. února porazil národní hokejový tým Rusko 1:0 v olympijském finále v Naganu, kdy byl brankář Dominik Hašek téměř nepřekonatelný a jediný gól vstřelil Petr Svoboda, čímž si země zajistila své první hokejové zlato." },
  { country: "cz", year: 1998, category: "Sport", text: "Ve věku 29 let získala Jana Novotná wimbledonský titul ve dvouhře žen, když ve finále porazila Nathalie Tauziatovou a stala se nejstarší prvoúspěšnou grandslamovou šampionkou otevřené éry." },
  { country: "cz", year: 1999, category: "Politics", text: "Dne 12. března vstoupila země formálně do NATO společně s Polskem a Maďarskem, když uložila své přístupové listiny v Independence ve státě Missouri, čímž potvrdila definitivní konec studené války ve střední Evropě." },
  { country: "cz", year: 2000, category: "Science & tech", text: "Volkswagen dokončil převzetí proslulé automobilky se sídlem v Mladé Boleslavi, když odkoupil zbývající vládní podíl a učinil tak z výrobce Octavie a Fabie zcela vlastněnou dceřinou společnost německého koncernu." },
  { country: "cz", year: 2000, category: "Culture", text: "Válečné drama Jana Hřebejka „Musíme si pomáhat“ o bezdětném páru, který před nacisty skrývá židovského souseda, mělo premiéru a vysloužilo si nominaci na Oscara za nejlepší cizojazyčný film." },
  { country: "cz", year: 2001, category: "Sport", text: "V rakouském Götzisu se desetibojař Roman Šebrle stal prvním atletem v historii, který překonal hranici 9 000 bodů, když v deseti disciplínách nasbíral světový rekord 9 026 bodů." },
  { country: "cz", year: 2001, category: "Science & tech", text: "Antivirotikum Viread, postavené na sloučenině tenofovir, kterou vyvinul chemik Antonín Holý v pražském Ústavu organické chemie a biochemie, získalo v USA schválení k léčbě HIV/AIDS a nakonec mělo pomoci milionům lidí po celém světě." },
  { country: "cz", year: 2002, category: "Upheaval", text: "V polovině srpna se Vltavou prohnala katastrofální „pětisetletá“ povodeň, nejhorší v zaznamenané historii země, jež zaplavila pražské čtvrti Karlín, Holešovice a Malou Stranu, zabila 17 lidí a vyhnala z domovů na 40 000 lidí." },
  { country: "cz", year: 2002, category: "Everyday life", text: "Když povodňová voda utopila v pražské zoo 134 zvířat, lachtan jménem Gaston unikl a po Vltavě a Labi doplaval až do německých Drážďan, kde vyčerpáním zahynul; stal se dojemným symbolem katastrofy a později byl uctěn sochou." },
  { country: "cz", year: 2002, category: "Politics", text: "Praha hostila první summit NATO, který se kdy konal v zemi bývalé Varšavské smlouvy, a aliance na něm vyzvala sedm nových členů, včetně sousedního Slovenska, k zahájení přístupových jednání." },
  { country: "cz", year: 2003, category: "Politics", text: "Václav Havel opustil Pražský hrad, když skončilo jeho druhé prezidentské období, a po třech kolech rozhárané volby ho jediným hlasem nahradil jeho starý rival, ekonom Václav Klaus." },
  { country: "cz", year: 2003, category: "Sport", text: "Záložník Juventusu Pavel Nedvěd získal Zlatý míč jako evropský fotbalista roku a stal se teprve druhým hráčem ze své země, který tuto cenu vyhrál, po Josefu Masopustovi v roce 1962." },
  { country: "cz", year: 2004, category: "Politics", text: "Dne 1. května vstoupila země formálně do Evropské unie v rámci historického „velkého třesku“ rozšíření, které najednou přijalo deset nových členských států." },
  { country: "cz", year: 2004, category: "Culture", text: "Sedmnáctiletá Aneta Langerová vyhrála první řadu pěvecké soutěže „Česko hledá SuperStar“, místní verze Pop Idol, když ve finále získala 79 procent hlasů a odstartovala popovou kariéru." },
  { country: "cz", year: 2004, category: "Sport", text: "Brankář Petr Čech podepsal smlouvu s Chelsea po tažení národního fotbalového týmu do semifinále Eura 2004 a poté byl oporou rekordní obrany Premier League s 24 čistými konty ve své první sezoně." },
  { country: "cz", year: 2005, category: "Sport", text: "Národní hokejový tým, opřený o čisté konto brankáře Tomáše Vokouna, porazil ve vídeňském finále Kanadu 3:0 a vyhrál mistrovství světa na turnaji, kde výluka v NHL uvolnila k účasti všechny hvězdy." },
  { country: "cz", year: 2005, category: "Culture", text: "V televizní anketě „Největší Čech“ zvítězil v hlasování veřejnosti fiktivní vševěd Jára Cimrman, byl však vyřazen, protože nebyl skutečnou osobou, takže oficiálním vítězem zůstal středověký král a císař Karel IV." },
  { country: "cz", year: 2005, category: "Everyday life", text: "Spotřeba piva dosáhla národního vrcholu 163,5 litru na osobu za rok, nejvíce na světě, když národ oddaných pijáků hltal značky jako Pilsner Urquell a Gambrinus." },
  { country: "cz", year: 2006, category: "Politics", text: "Červnové parlamentní volby vyústily v ochromující patovou situaci, kdy středopravý i levicový blok držely každý přesně 100 z 200 křesel, takže země zůstala měsíce bez fungující vlády." },
  { country: "cz", year: 2007, category: "Politics", text: "Spojené státy zahájily jednání o výstavbě protiraketového radaru ve vojenském prostoru Brdy mezi Prahou a Plzní, což byl plán, který vyvolal vytrvalé veřejné protesty a místní referenda drtivě proti němu." },
  { country: "cz", year: 2007, category: "Everyday life", text: "Dne 21. prosince vstoupila země do schengenského prostoru a ze dne na den byly zrušeny hraniční přechody podél pozemních hranic s Německem, Rakouskem, Polskem a Slovenskem, takže lidé je poprvé po generace mohli volně překračovat." },
  { country: "cz", year: 2008, category: "Politics", text: "Prezident Václav Klaus byl v únoru parlamentem znovu zvolen na druhé pětileté období, opět o jediný hlas, po dalším kole vyhroceně sporné volby." },
  { country: "cz", year: 2009, category: "Politics", text: "Země poprvé předsedala Evropské unii v rámci rotujícího předsednictví, jen aby se středopravá vláda Mirka Topolánka uprostřed mandátu zhroutila poté, co prohrála hlasování o nedůvěře, a vedením úřednického kabinetu byl pověřen statistik Jan Fischer." },
  { country: "cz", year: 2009, category: "Culture", text: "Umělec David Černý odhalil v budově Rady EU v Bruselu dílo „Entropa“, obří mozaiku zesměšňující národní stereotypy, o níž se ukázalo, že jde o mystifikaci, kterou vytvořil on sám se svými asistenty, a nikoli o práci umělců ze všech 27 členských států, což vyvolalo diplomatickou bouři." },
  { country: "cz", year: 2009, category: "Politics", text: "V září zrušila Obamova administrativa plánovaný protiraketový radar v Brdech poté, co přehodnotila své posouzení íránské hrozby, čímž ukončila jeden z nejrozporuplnějších zahraničněpolitických sporů desetiletí." },
  { country: "cz", year: 2009, category: "Everyday life", text: "Poslední úsek dálnice spojující Ostravu s celostátní dálniční sítí byl otevřen jako součást D1, čímž bylo završeno desetiletí rozsáhlých investic financovaných státem a EU do rozšiřující se silniční sítě země." },
  { country: "cz", year: 2010, category: "Sport", text: "Národní hokejový tým s kapitánem, zkušenou hvězdou Jaromírem Jágrem, získal zlato na mistrovství světa v Německu, když ve finále porazil Rusko 2:1." },
  { country: "cz", year: 2010, category: "Politics", text: "Po parlamentních volbách na konci května získali nejvíce hlasů sociální demokraté, přesto se moci ujala koalice tří středopravých stran pod vedením premiéra Petra Nečase, který prosadil program krizových úsporných opatření." },
  { country: "cz", year: 2011, category: "Sport", text: "Levoruká silová hráčka Petra Kvitová, tehdy teprve jednadvacetiletá, získala svůj první wimbledonský titul ve dvouhře, když porazila Marii Šarapovovou, čímž korunovala průlomový rok, který ji vynesl na vrchol ženského tenisu." },
  { country: "cz", year: 2011, category: "Sport", text: "V čele s Kvitovou porazil ženský tenisový tým v Moskvě Rusko a získal pro zemi první titul ve Fed Cupu coby samostatného státu." },
  { country: "cz", year: 2011, category: "People", text: "Václav Havel, disidentský dramatik, který se stal posledním prezidentem Československa a prvním postkomunistické republiky, zemřel 18. prosince ve věku 75 let ve svém venkovském domě na Hrádečku." },
  { country: "cz", year: 2011, category: "Culture", text: "Havlův státní pohřeb se konal v gotické katedrále svatého Víta na Pražském hradě a přilákal truchlící a státníky z více než třiceti zemí, mezi nimi Billa a Hillary Clintonovy." },
  { country: "cz", year: 2012, category: "Upheaval", text: "Vlna otrav metanolem z pančovaného alkoholu naředěného průmyslovým lihem zabila desítky lidí a vyvolala dočasný celostátní zákaz prodeje veškerých lihovin nad 20 procent, jemuž místní říkali „metanolová prohibice“." },
  { country: "cz", year: 2012, category: "Politics", text: "Parlament schválil ústavní novelu zavádějící přímou volbu prezidenta lidem, čímž ukončil dvě desetiletí, během nichž hlavu státu vybíralo společné zasedání parlamentu." },
  { country: "cz", year: 2013, category: "Politics", text: "V první přímé prezidentské volbě v historii porazil bývalý premiér Miloš Zeman v lednovém druhém kole ministra zahraničí Karla Schwarzenberga, když získal zhruba 55 procent hlasů." },
  { country: "cz", year: 2013, category: "Politics", text: "Odcházející prezident Václav Klaus si připomněl dvacáté výročí republiky rozsáhlou novoroční amnestií, jež zastavila několik dlouho běžících korupčních procesů, čímž vyvolal petice a veřejné rozhořčení." },
  { country: "cz", year: 2013, category: "Upheaval", text: "Vydatné červnové deště rozvodnily Vltavu a další řeky, což přimělo vládu vyhlásit stav nouze v sedmi krajích, uzavřít stanice metra v centru Prahy a evakuovat přes 19 000 lidí." },
  { country: "cz", year: 2013, category: "Politics", text: "Premiér Petr Nečas v červnu rezignoval poté, co byla jeho šéfka kabinetu a důvěrnice Jana Nagyová zatčena za zneužití pravomoci, skandál zahrnující tajné sledování jeho manželky, který svrhl celý kabinet." },
  { country: "cz", year: 2013, category: "Everyday life", text: "Tváří v tvář recesi a hrozbě deflace začala centrální banka v listopadu zasahovat na devizových trzích, aby oslabila korunu, a zavázala se zabránit jejímu posílení pod 27 za euro." },
  { country: "cz", year: 2014, category: "Politics", text: "Sociální demokrat Bohuslav Sobotka složil přísahu jako premiér v čele koalice, v níž miliardář Andrej Babiš a jeho nové hnutí ANO obsadili ministerstvo financí." },
  { country: "cz", year: 2014, category: "Sport", text: "Na zimních olympijských hrách v Soči si dvacetiletá Eva Samková, závodící pro štěstí s namalovaným knírkem, dojela pro zlato ve snowboardcrossu žen." },
  { country: "cz", year: 2014, category: "Sport", text: "Rychlobruslařka Martina Sáblíková úspěšně obhájila v Soči svůj olympijský titul na 5 000 metrů a přidala stříbro na 3 000 metrů." },
  { country: "cz", year: 2014, category: "Upheaval", text: "Dvě obrovské exploze zničily muniční sklady ve Vrběticích na jihovýchodě a zabily dva muže; tyto výbuchy české úřady později připsaly důstojníkům ruské vojenské rozvědky." },
  { country: "cz", year: 2014, category: "Sport", text: "Petra Kvitová získala svůj druhý wimbledonský titul ve dvouhře, když ve finále, jež trvalo necelou hodinu, rozdrtila Kanaďanku Eugenie Bouchardovou 6:3, 6:0." },
  { country: "cz", year: 2015, category: "Politics", text: "Vláda se připojila k Maďarsku, Slovensku a Rumunsku v hlasování proti plánu EU přerozdělovat uprchlíky podle kvót a prezident Zeman ve svém vánočním poselství označil migrační vlnu za „organizovanou invazi“." },
  { country: "cz", year: 2016, category: "Politics", text: "Vláda schválila „Czechia“ jako oficiální krátký anglický název země, který byl v červenci řádně zapsán do databází názvů zemí Organizace spojených národů." },
  { country: "cz", year: 2016, category: "Everyday life", text: "Ministerstvo financí pod vedením Andreje Babiše zavedlo systém elektronické evidence tržeb EET, počínaje restauracemi, hotely a kavárnami, které musely v reálném čase odesílat každou účtenku finanční správě." },
  { country: "cz", year: 2017, category: "Everyday life", text: "Dlouho diskutovaný zákaz kouření ve vnitřních prostorách vstoupil v platnost 31. května a konečně vyčistil opar z oblíbených hospod, restaurací a barů v zemi." },
  { country: "cz", year: 2017, category: "Sport", text: "Horolezec Adam Ondra jako první přelezl 45metrovou cestu ve Flatangeru v Norsku, pojmenoval ji „Silence“ a navrhl pro ni obtížnost 9c, čímž z ní učinil nejtěžší sportovní lezeckou cestu na světě." },
  { country: "cz", year: 2017, category: "Politics", text: "Hnutí ANO Andreje Babiše získalo v říjnových parlamentních volbách téměř třetinu hlasů a v prosinci se stal nejbohatším člověkem, který byl kdy jmenován premiérem." },
  { country: "cz", year: 2018, category: "Sport", text: "Na zimních olympijských hrách v Pchjongčchangu šokovala Ester Ledecká sportovní svět, když o setinu sekundy vyhrála alpský super-G a poté získala druhé zlato v paralelním obřím slalomu na snowboardu, jako vůbec první sportovec se zlatem na lyžích i na snowboardu na týchž hrách." },
  { country: "cz", year: 2018, category: "Politics", text: "Prezident Miloš Zeman, kandidující na protiimigrační platformě, těsně vyhrál druhé pětileté období v lednovém druhém kole, když porazil bývalého předsedu Akademie věd Jiřího Drahoše se zhruba 51 procenty." },
  { country: "cz", year: 2018, category: "Science & tech", text: "Zařízení ELI Beamlines v Dolních Břežanech u Prahy, kde sídlí jedny z nejvýkonnějších laserů na světě, se otevřelo externím výzkumníkům." },
  { country: "cz", year: 2019, category: "Upheaval", text: "V červnu zaplnila čtvrt milionu lidí pražskou Letnou na shromáždění pořádaném hnutím „Milion chvilek pro demokracii“, aby požadovali rezignaci premiéra Babiše, což byla největší demonstrace od sametové revoluce roku 1989." },
  { country: "cz", year: 2019, category: "Everyday life", text: "Země opět vévodila světu ve spotřebě piva, když občané vypili hluboko přes 130 litrů na osobu za rok z pivovarů jako Pilsner Urquell, Staropramen a Budweiser Budvar." },
  { country: "cz", year: 2020, category: "Everyday life", text: "Dne 19. března se stala první evropskou zemí, která zavedla povinné nošení roušek na veřejnosti, a během několika týdnů bzučely domácí šicí stroje, jak občané šili látkové roušky pro sousedy a nemocnice." },
  { country: "cz", year: 2020, category: "Upheaval", text: "První tři případy COVID-19 byly potvrzeny 1. března a do 12. března vyhlásila vláda třicetidenní stav nouze a brzy uzavřela hranice cizincům." },
  { country: "cz", year: 2020, category: "Politics", text: "V říjnových krajských volbách zvítězilo hnutí ANO premiéra Andreje Babiše v deseti ze třinácti krajů, přičemž voliči odevzdávali hlasy v rouškách." },
  { country: "cz", year: 2021, category: "Upheaval", text: "Večer 24. června se vzácné tornádo síly F4 o šířce až 3,5 kilometru prohnalo obcemi na jižní Moravě, zabilo šest lidí, téměř 600 zranilo a srovnalo se zemí celé části Hrušek a Moravské Nové Vsi." },
  { country: "cz", year: 2021, category: "Sport", text: "Barbora Krejčíková získala trofej ve dvouhře na French Open a téhož roku ještě vyhrála olympijské zlato ve čtyřhře v Tokiu." },
  { country: "cz", year: 2021, category: "Politics", text: "Středopravá koalice Spolu o méně než procentní bod přemohla Babišovo ANO v nejtěsnějších parlamentních volbách v historii země, přičemž staré komunistická a sociálnědemokratická strana poprvé nezískaly ani jediné křeslo." },
  { country: "cz", year: 2021, category: "Science & tech", text: "Kyberbezpečnostní firma Avast se sídlem v Praze v srpnu odsouhlasila mnohamiliardovou fúzi s americkou společností NortonLifeLock, čímž vznikla jedna z největších firem na zabezpečení pro spotřebitele na světě." },
  { country: "cz", year: 2022, category: "Sport", text: "Na zimních olympijských hrách v Pekingu obhájila Ester Ledecká svůj titul v paralelním obřím slalomu na snowboardu a získala tak první zlato země na těchto hrách a své třetí kariérní olympijské zlato." },
  { country: "cz", year: 2022, category: "Upheaval", text: "Po ruské invazi na Ukrajinu přijala země během měsíce přes 300 000 uprchlíků a na konci roku hostila nejvyšší počet vysídlených Ukrajinců na obyvatele v EU." },
  { country: "cz", year: 2022, category: "Everyday life", text: "Když inflace vyšplhala k 18 procentům a účty za energie tvrdě dolehly, sešlo se 3. září na pražském Václavském náměstí kolem 70 000 lidí na protest proti krizi životních nákladů." },
  { country: "cz", year: 2022, category: "Politics", text: "Země ve druhé polovině roku předsedala Radě Evropské unie v rámci rotujícího předsednictví a řídila politiku EU ve chvíli, kdy se horečně snažila reagovat na válku a energetický šok." },
  { country: "cz", year: 2023, category: "Politics", text: "Generál NATO ve výslužbě Petr Pavel vyhrál druhé kolo prezidentské volby proti Andreji Babišovi s 58 procenty hlasů a 9. března se ujal úřadu na pevně prozápadní, proukrajinské platformě." },
  { country: "cz", year: 2023, category: "Sport", text: "Markéta Vondroušová se stala vůbec první nenasazenou ženou, která vyhrála wimbledonský titul ve dvouhře, když ve finále porazila Ons Jabeurovou." },
  { country: "cz", year: 2023, category: "Upheaval", text: "Dne 21. prosince zahájil postgraduální student střelbu na Filozofické fakultě Univerzity Karlovy v centru Prahy a zabil 14 lidí v události, kterou prezident označil za nejtragičtější v dějinách národa." },
  { country: "cz", year: 2023, category: "People", text: "Karel Schwarzenberg, šlechtic kouřící doutníky a bývalý ministr zahraničí, který pomohl řídit integraci země na Západ, zemřel ve věku 85 let na klinice ve Vídni." },
  { country: "cz", year: 2023, category: "Everyday life", text: "Dne 1. ledna si země a sousední Slovensko připomněly třicet let od pokojného „sametového rozvodu“, který rozdělil Československo na dva samostatné státy." },
  { country: "cz", year: 2024, category: "Sport", text: "Hnán vyprodaným pražským publikem porazil národní hokejový tým ve finále mistrovství světa Švýcarsko 2:0, přičemž vítězný gól vstřelil David Pastrňák, čímž si zajistil první titul mistrů světa na domácím ledě od roku 2010." },
  { country: "cz", year: 2024, category: "Upheaval", text: "V polovině září vylila bouře Boris přes 500 milimetrů srážek na pohoří Jeseníky, čímž spustila povodně, jež zabily pět lidí, přes 13 000 vyhnaly z domovů a zdevastovaly města jako Opava a Ostrava." },
  { country: "cz", year: 2024, category: "Politics", text: "Muniční iniciativa vedená Českem a v jejímž čele stál prezident Pavel dodala Ukrajině zhruba 1,5 milionu dělostřeleckých granátů, které sháněla mimo Evropu ve chvíli, kdy ostatní západní pomoc kolísala." },
  { country: "cz", year: 2024, category: "Everyday life", text: "Průměrná hrubá měsíční mzda dosáhla zhruba 46 000 korun, přesto se cena typického staršího pražského bytu o 70 metrech čtverečních blížila 10 milionům korun, čímž se vlastní bydlení v hlavním městě stalo pro mnohé nedosažitelné." },
  { country: "cz", year: 2024, category: "Sport", text: "Barbora Krejčíková získala svůj druhý grandslamový titul ve dvouhře, když ve finále Wimbledonu porazila Jasmine Paoliniovou a stala se čtvrtou Češkou, která tuto trofej získala." },
  { country: "cz", year: 2024, category: "Culture", text: "Zkušený filmový herec Ivan Trojan obdržel na 58. ročníku Mezinárodního filmového festivalu v Karlových Varech Cenu prezidenta festivalu za mimořádný přínos českému filmu." },
  { country: "cz", year: 2025, category: "Politics", text: "Andrej Babiš a jeho hnutí ANO se v říjnových parlamentních volbách vrátili k moci s 34,5 procenta hlasů a premiér Petr Fiala uznal porážku po jediném volebním období." },
  { country: "cz", year: 2025, category: "Everyday life", text: "Země si ponechala svou korunu a titul národa, který na světě vypije nejvíce piva, i když nová vláda tiše odložila jakýkoli harmonogram přijetí eura." },
  { country: "cz", year: 2026, category: "Politics", text: "Vláda vedená Babišem přikročila ke zrušení každoroční zprávy hodnotící připravenost na vstup do eurozóny, čímž dala najevo, že přijetí eura je v dohledné době mimo program." },
  { country: "ua", year: 1930, category: "Culture", text: "Oleksandr Dovženko uvedl své němé veledílo Země, lyrickou ódu na půdu a venkovský život, kterou cenzoři během několika dní zakázali, ač ji filmoví historici později zařadili mezi nejlepší filmy všech dob." },
  { country: "ua", year: 1930, category: "Politics", text: "Stalinova nucená kolektivizace se prohnala venkovem, když komunističtí agitátoři zaháněli rolníky do kolchozů a ty, kdo se vzpírali, označovali za „kulaky“ určené k likvidaci jakožto třída." },
  { country: "ua", year: 1930, category: "Upheaval", text: "Ve východní Haliči pod polskou správou rozpoutaly úřady „pacifikační“ kampaň hromadného zatýkání, bití a ničení majetku namířenou proti ukrajinskému obyvatelstvu jako odpověď na vlnu nacionalistických sabotáží." },
  { country: "ua", year: 1930, category: "People", text: "Lina Kostenková, jež se měla stát jedním z nejuctívanějších literárních hlasů národa a přední postavou tzv. šedesátníků, se narodila 19. března." },
  { country: "ua", year: 1931, category: "People", text: "Nejvýznamnější národní historik Mychajlo Hruševskyj, autor monumentálních desetisvazkových Dějin Ukrajiny-Rusi, byl vykázán do Moskvy pod neustálým dohledem tajné policie." },
  { country: "ua", year: 1932, category: "Science & tech", text: "Rozlehlá Dněperská vodní elektrárna v Záporoží, tehdy největší elektrárna v Evropě, začala vyrábět elektřinu zpoza své 760 metrů dlouhé přehrady napříč velkou řekou." },
  { country: "ua", year: 1932, category: "Politics", text: "Nechvalně známý „zákon o klasech“ ze 7. srpna učinil ze sebrání byť jen hrstky obilných klasů z družstevního pole zločin krádeže socialistického majetku, trestaný zastřelením nebo deseti lety v táborech." },
  { country: "ua", year: 1932, category: "Everyday life", text: "Když prosincový výnos o vnitřních pasech připoutal rolníky k venkovu, hladovějící rodiny mohly nakupovat jen ve státních prodejnách Torgsin, kde odevzdávaly snubní prsteny a zlaté rodinné památky za trochu mouky nebo chleba." },
  { country: "ua", year: 1932, category: "Upheaval", text: "Celé vesnice, které nesplnily nemožné obilné kvóty, byly zapsány na „černé listiny“, tajná policie je obklíčila, odepřela jim veškerý obchod i zboží a nechala je hladovět jako úmyslný trest." },
  { country: "ua", year: 1933, category: "Upheaval", text: "Uměle vyvolaný hladomor známý jako holodomor dosáhl svého vražedného vrcholu na jaře, kdy nastala většina ze zhruba 3,9 milionu úmrtí hladem a z vylidněného venkova přicházely zprávy o kanibalismu." },
  { country: "ua", year: 1933, category: "People", text: "Na zoufalý protest proti ničení svého národa a zatčení blízkého spisovatelského kolegy se modernistický autor Mykola Chvyljovyj 13. května zastřelil ve svém charkovském bytě." },
  { country: "ua", year: 1933, category: "Culture", text: "Kulturní rozkvět dvacátých let se zvrhl v „popravenou renesanci“, když strana zvrátila ukrajinizaci a obrátila svůj represivní aparát proti spisovatelům, vědcům a umělcům země." },
  { country: "ua", year: 1933, category: "People", text: "Mykola Skrypnyk, bolševický komisař, který prosazoval ukrajinizaci škol a státní správy, si vzal život, místo aby odvolal svou politiku, kterou Stalinovi lidé rozbíjeli." },
  { country: "ua", year: 1934, category: "Politics", text: "V červnu bylo hlavní město republiky přeneseno z Charkova do starobylého Kyjeva na Dněpru, čímž se historickému centru navrátila role sídla vlády." },
  { country: "ua", year: 1934, category: "Science & tech", text: "První specializované svářečské výzkumné centrum na světě, Institut elektrického svařování vedený inženýrem Jevhenem Patonem, bylo formálně založeno v Kyjevě a stalo se průkopníkem automatického svařování pod tavidlem." },
  { country: "ua", year: 1934, category: "People", text: "Mychajlo Hruševskyj zemřel ve věku 68 let v kavkazských lázních Kislovodsk krátce po rutinní operaci, přičemž jeho poslední léta provázelo pronásledování." },
  { country: "ua", year: 1935, category: "Everyday life", text: "V noci na 31. srpna vytěžil donbaský horník Alexej Stachanov za jedinou směnu 102 tun uhlí, čtrnáctkrát víc než jeho norma, čímž odstartoval stachanovské hnutí rekordů lámajících úderníků." },
  { country: "ua", year: 1936, category: "Sport", text: "Dynamo Kyjev se zúčastnilo úplně prvního sovětského fotbalového mistrovství a skončilo druhé za Spartakem Moskva, čímž začal jeho život v nejvyšší soutěži, z níž už klub nikdy nesestoupil." },
  { country: "ua", year: 1936, category: "Sport", text: "Když byla tělesná kultura centralizována pod nový celosvazový výbor, otevřely se první státní sportovní školy pro děti, jež nasměrovaly mládež k oficiálně organizovanému sportu." },
  { country: "ua", year: 1937, category: "Politics", text: "Koncem ledna přijala republika novou ústavu podle vzoru Stalinovy charty z roku 1936, slibující přímé, rovné a tajné volby do sovětů, a to i ve chvíli, kdy zuřil velký teror." },
  { country: "ua", year: 1937, category: "Culture", text: "Během čtyř dnů na přelomu října a listopadu zastřelila NKVD stovky předních myslitelů národa na popravišti Sandarmoch v Karélii, mezi nimi divadelního vizionáře Lese Kurbase a dramatika Mykolu Kuliše." },
  { country: "ua", year: 1937, category: "Everyday life", text: "Sovětské sčítání lidu zaznamenalo populaci natolik zdecimovanou hladomorem a represemi, že jeho výsledky byly utajeny a jeho organizátoři sami zatčeni za vytvoření „škůdcovských“ čísel." },
  { country: "ua", year: 1938, category: "Politics", text: "Voliči přišli k urnám v prvních volbách do nového Nejvyššího sovětu republiky, rituálu s jediným kandidátem, který na vrcholu čistek potvrdil sevření strany." },
  { country: "ua", year: 1939, category: "Upheaval", text: "Po paktu Molotov-Ribbentrop zabraly sovětské síly v září Polsku východní Halič a Volyň, čímž spojily západní území se sovětskou republikou a Lvov dostaly pod sovětskou nadvládu." },
  { country: "ua", year: 1939, category: "People", text: "Slavná sopranistka Solomija Krušelnycka, diva, jíž se připisuje záchrana Pucciniho Madama Butterfly, se vrátila z Itálie do svého domova ve Lvově pouhé týdny předtím, než dorazili Sověti." },
  { country: "ua", year: 1939, category: "Everyday life", text: "Židovská komunita v Kyjevě čítala na 224 000 lidí, více než čtvrtinu obyvatel města, a udržovala jidiš školy, divadlo a pulzující literární život." },
  { country: "ua", year: 1940, category: "Politics", text: "Po sovětském záboru východního Polska z předchozího podzimu se miliony Poláků, Ukrajinců a Židů v nově anektované Haliči a Volyni ocitly jako občané rozšířené sovětské republiky, jejich hospodářství byla zkolektivizována a jejich elity určeny k deportaci na Sibiř." },
  { country: "ua", year: 1940, category: "Politics", text: "Koncem června vpochodovala Rudá armáda po ultimátu Rumunsku do severní Bukoviny a oblasti Herca a město Černovice s okolními zeměmi bylo v srpnu začleněno do sovětské republiky." },
  { country: "ua", year: 1940, category: "People", text: "Ivan Kožedub, mladý letecký nadšenec z vesnice v Sumské oblasti, zahajoval letecký výcvik, který z něj měl udělat nejúspěšnější spojenecké stíhací eso celé druhé světové války s 62 potvrzenými sestřely." },
  { country: "ua", year: 1941, category: "Upheaval", text: "Večer 18. srpna ustupující jednotky NKVD odpálily velkou Dněperskou vodní přehradu v Záporoží a uvolněná povodňová vlna utopila níže po proudu desetitisíce civilistů a sovětských vojáků." },
  { country: "ua", year: 1941, category: "Upheaval", text: "Německé síly vstoupily do hlavního města 19. září a o deset dní později, 29. a 30. září, bylo téměř 34 000 Židů odvedeno k rokli Babí Jar a zastřeleno v jednom z největších jednotlivých masakrů holocaustu." },
  { country: "ua", year: 1941, category: "Politics", text: "Jak se fronta valila na východ, začalo 30. října dlouhé obléhání černomořské pevnosti Sevastopol mocnostmi Osy, zatímco přístav Oděsa přečkal před svou evakuací 73 dní obrany." },
  { country: "ua", year: 1941, category: "Science & tech", text: "Svářečský institut Jevhena Patona, evakuovaný na Ural, zdokonalil automatické svařování pancéřových plátů pod tavidlem, průlom, jenž sovětským továrnám umožnil svařovat korby tanků T-34 mnohem rychleji, než dokázal nepřítel." },
  { country: "ua", year: 1942, category: "Sport", text: "Dne 9. srpna porazilo v okupovaném Kyjevě mužstvo bývalých fotbalistů Dynama a Lokomotivu hrající pod názvem FC Start německý vojenský tým 5:3 v zápase později opředeném mýtem jako hrdinský „zápas smrti“." },
  { country: "ua", year: 1942, category: "Politics", text: "Ukrajinští nacionalisté z banderovské frakce OUN vytvořili na Volyni Ukrajinskou povstaleckou armádu (UPA) a zahájili partyzánské tažení, které léta bojovalo proti Němcům i Sovětům." },
  { country: "ua", year: 1942, category: "Upheaval", text: "Sevastopol padl 4. července silám Ericha von Mansteina po osmiměsíčním obléhání tak ničivém, že sovětští obránci utrpěli kolem 200 000 ztrát, včetně asi 95 000 zajatých při závěrečném zhroucení." },
  { country: "ua", year: 1943, category: "Upheaval", text: "Po rozsáhlé bitvě o Dněpr dobyla Rudá armáda pod velením generála Nikolaje Vatutina v časných ranních hodinách 6. listopadu zpět hlavní město, kde po 778 dnech okupace nalezla velkou část nábřeží vyhozenou do povětří ustupujícími Němci." },
  { country: "ua", year: 1943, category: "People", text: "Roman Šuchevyč převzal koncem léta velení Ukrajinské povstalecké armády a stal se nepolapitelným vůdcem podzemního odboje, který Sověti pronásledovali po zbytek desetiletí." },
  { country: "ua", year: 1943, category: "Culture", text: "Slavný filmový režisér Oleksandr Dovženko dokončil svůj scénář „Ukrajina v plamenech“, jen aby jej Stalin osobně odsoudil za „nacionalistické nálady“ a umělci navždy zakázal vrátit se do vlasti." },
  { country: "ua", year: 1944, category: "Upheaval", text: "Během tří dnů počínaje 18. květnem nahnala NKVD prakticky celou populaci krymských Tatarů, přes 190 000 lidí, do dobytčích vagonů a na Stalinův rozkaz o kolektivním trestu je deportovala do Střední Asie, kde jich značná část brzy zemřela hladem a na nemoci." },
  { country: "ua", year: 1944, category: "Politics", text: "Jak se fronta hnala na západ a Rudá armáda toho podzimu vstoupila do Zakarpatska, vyhlásil 26. listopadu mukačevský sjezd lidových výborů své přání sjednotit region se sovětskou republikou." },
  { country: "ua", year: 1945, category: "Politics", text: "Dne 26. června podepsala republika v San Francisku Chartu Organizace spojených národů jako zakládající člen s vlastním křeslem ve Valném shromáždění, což byl diplomatický tah, jenž dal Moskvě v novém světovém orgánu tři hlasy." },
  { country: "ua", year: 1945, category: "People", text: "Stíhací eso Ivan Kožedub, který absolvoval 330 bojových letů a ani jednou nebyl sestřelen, obdržel v srpnu svou třetí hvězdu Hrdiny Sovětského svazu poté, co se stal také prvním sovětským pilotem, jenž sestřelil německý proudový letoun Me 262." },
  { country: "ua", year: 1945, category: "Politics", text: "Dne 29. června Československo formálně postoupilo Zakarpatsko Sovětskému svazu, čin, který poprvé sjednotil téměř všechna etnicky ukrajinská území v jediném státě." },
  { country: "ua", year: 1946, category: "Everyday life", text: "Nejhorší sucho od roku 1891 zničilo sklizeň, zatímco stát odmítl snížit obilné kvóty a omezil nárok na příděly, čímž vyvolal hladomor, jenž jen v samotné republice zabil na 300 000 lidí." },
  { country: "ua", year: 1946, category: "Culture", text: "Na vynuceném „synodu“ ve Lvově ve dnech 8.–10. března sovětské úřady násilně zrušily Ukrajinskou řeckokatolickou církev a její farnosti pohltily do Ruské pravoslavné církve, čímž zahnaly věřící na více než čtyři desetiletí do ilegality." },
  { country: "ua", year: 1946, category: "Everyday life", text: "Zakarpatsko se svými horskými vesnicemi a městem Užhorod bylo zorganizováno jako Zakarpatská oblast a začalo se začleňovat do sovětského hospodářského a kulturního života." },
  { country: "ua", year: 1947, category: "Politics", text: "Na Stalinův rozkaz nahradil na jaře během hladomorové krize Lazar Kaganovič Nikitu Chruščova ve funkci šéfa strany, jenže do konce roku byl Chruščov do úřadu navrácen." },
  { country: "ua", year: 1947, category: "Science & tech", text: "V březnu byla obnovena výroba elektřiny v přestavěné Dněperské vodní elektrárně, jejíž zničené turbíny byly zčásti nahrazeny novými generátory dovezenými od General Electric z Ameriky." },
  { country: "ua", year: 1947, category: "People", text: "Sofija Rotaru, jež se měla stát jednou z nejmilovanějších popových zpěvaček Sovětského svazu, se narodila 7. srpna do etnicky moldavské rodiny ve vesnici v Černovické oblasti." },
  { country: "ua", year: 1948, category: "Everyday life", text: "Hromadné hladovění po úspěšnější sklizni ustoupilo, venkovský život však zůstal ponurý, neboť rolníci dřeli v kolchozech s pramálo výsledky pod státem, který si dodávky obilí cenil více než jejich přežití." },
  { country: "ua", year: 1949, category: "Politics", text: "Dlouhé Chruščovovo působení ve funkci stranického šéfa republiky skončilo, když byl v prosinci odvolán do Moskvy a zanechal za sebou zemi, kde pokračovala poválečná sovětizace nově anektovaného západu a potlačování povstání UPA." },
  { country: "ua", year: 1950, category: "Upheaval", text: "Dne 5. března byl Roman Šuchevyč, vrchní velitel Ukrajinské povstalecké armády, zabit při přestřelce se sovětskými bezpečnostními jednotkami, které obklíčily jeho úkryt ve vesnici Biohorča na okraji Lvova, čímž zasadily nacionalistickému podzemí ochromující ránu." },
  { country: "ua", year: 1950, category: "Science & tech", text: "V září začaly na dolním Dněpru práce na rozlehlé Kachovské vodní elektrárně, vlajkové lodi Stalinova „velkého plánu přeměny přírody“, jež měla zatopit vesnice a vytvořit vnitrozemské moře pro výrobu elektřiny a zavlažování." },
  { country: "ua", year: 1950, category: "People", text: "Viktor Janukovyč, budoucí prezident, jenž měl uprchnout ze země během povstání Euromajdan v roce 2014, se narodil 9. července ve vesnici poblíž donbaského průmyslového města Jenakijeve." },
  { country: "ua", year: 1951, category: "Upheaval", text: "Hromadné deportace ze západních oblastí pokračovaly jako součást poválečné kampaně, která vykořenila statisíce lidí za odpor, náboženskou věrnost nebo odmítání vstoupit do kolchozů, přičemž mnozí byli posláni do zvláštních osad na Sibiři a na dalekém severu." },
  { country: "ua", year: 1951, category: "Everyday life", text: "Ukrajinská řeckokatolická církev, formálně zlikvidovaná na sovětsky zinscenovaném lvovském „soboru“ z roku 1946, přežívala jen jako tajná síť kněží sloužících utajené bohoslužby v domech a lesích pod neustálou hrozbou zatčení." },
  { country: "ua", year: 1952, category: "Science & tech", text: "Letecká konstrukční kancelář Olega Antonova byla přemístěna do Kyjeva, čímž zapustila kořeny leteckého průmyslu, který měl jednou v hlavním městě republiky stavět největší nákladní letadla na světě." },
  { country: "ua", year: 1952, category: "Sport", text: "V Helsinkách, na vůbec prvních olympijských hrách, jichž se Sovětský svaz zúčastnil, vyšel gymnasta Viktor Čukarin, jenž přežil nacistické zajatecké tábory, jako nejúspěšnější mužský atlet her se čtyřmi zlatými a dvěma stříbrnými medailemi." },
  { country: "ua", year: 1952, category: "Sport", text: "Gymnastka Nina Bočarovová, rodačka z Poltavy, získala na hrách v Helsinkách olympijské zlato na kladině a stříbro ve víceboji a stala se vůbec první olympijskou šampionkou na kladině v historii." },
  { country: "ua", year: 1953, category: "Politics", text: "V červnu se Oleksij Kyryčenko stal prvním tajemníkem Komunistické strany Ukrajiny, prvním etnickým Ukrajincem v čele strany republiky od 20. let, což signalizovalo částečné zmírnění pozdně stalinské rusifikace." },
  { country: "ua", year: 1953, category: "Everyday life", text: "Po Stalinově smrti v březnu začala rozsáhlá amnestie vyprazdňovat pracovní tábory a v následujících letech se statisíce propuštěných vězňů vracely do měst a vesnic po celé republice." },
  { country: "ua", year: 1954, category: "Politics", text: "Dne 19. února byl Krymský poloostrov sovětským výnosem formálně převeden z Ruské federace do ukrajinské republiky, což bylo zdůvodněno hospodářskou závislostí Krymu na pevnině a načasováno k velkolepému výročnímu jubileu." },
  { country: "ua", year: 1954, category: "Culture", text: "Honosné státní oslavy připomněly 300. výročí Perejaslavské dohody z roku 1654 vážící kozácké země k Moskvě a město Proskuriv bylo přejmenováno na Chmelnyckyj podle kozáckého hejtmana." },
  { country: "ua", year: 1954, category: "Sport", text: "Dynamo Kyjev poprvé získalo Sovětský pohár, když v deštěm zmáčeném moskevském finále porazilo Spartak Jerevan, raný triumf klubu, jenž se měl stát vlajkonošem fotbalu v republice." },
  { country: "ua", year: 1954, category: "People", text: "Viktor Juščenko, budoucí prezident, jenž měl přežít otravu dioxinem a vést oranžovou revoluci roku 2004, se narodil 23. února do učitelské rodiny ve vesnici Choruživka v Sumské oblasti." },
  { country: "ua", year: 1955, category: "Science & tech", text: "Dne 18. října začala první turbína Kachovské vodní elektrárny vyrábět energii a stoupající voda se začala plnit do nádrže, která nakonec zatopila přes dva tisíce čtverečních kilometrů údolí Dněpru." },
  { country: "ua", year: 1955, category: "Everyday life", text: "Rozsáhlá amnestie propustila většinu zbývajících vězňů táborů a navrátila veterány nacionalistického podzemí i obyčejné vězně rodinám, které je často považovaly za mrtvé." },
  { country: "ua", year: 1956, category: "Politics", text: "Chruščovův „tajný projev“ odsuzující Stalinovy zločiny na XX. sjezdu strany v únoru zahájil kulturní a politické uvolnění známé jako tání, jež zmírnilo cenzuru a urychlilo rehabilitaci obětí čistek." },
  { country: "ua", year: 1956, category: "People", text: "Dne 25. listopadu zemřel průkopnický filmař Oleksandr Dovženko, mistr poetického filmu, na infarkt na své dače poblíž Moskvy, přičemž několik milovaných projektů zůstalo nedokončeno." },
  { country: "ua", year: 1957, category: "Politics", text: "Oleksij Kyryčenko byl jako blízký Chruščovův spojenec povýšen do Moskvy a stal se druhou nejvýše postavenou osobou v celém vedení sovětské strany hned po samotném Chruščovovi." },
  { country: "ua", year: 1957, category: "Culture", text: "Kyjevské filmové studio bylo oficiálně pojmenováno Filmové studio Dovženka na památku režiséra, jenž zemřel rok předtím, čímž se upevnilo jako srdce kinematografie republiky." },
  { country: "ua", year: 1958, category: "Science & tech", text: "Charkovské těžkostrojírenské závody postavily tři obří pásové polární vozy „Charkovčanka“, pojízdné obytné stroje s palandami, kuchyňkou a dílnou, navržené k převozu sovětských vědců přes antarktický led." },
  { country: "ua", year: 1959, category: "Science & tech", text: "Vozy Charkovčanka vyrobené v Charkově dotáhly v prosinci sovětskou expedici až k zeměpisnému jižnímu pólu, čímž předvedly inženýrskou sílu těžkého průmyslu republiky." },
  { country: "ua", year: 1959, category: "Sport", text: "Dne 29. května debutoval dvacetiletý Valerij Lobanovskyj v nejvyšší soutěži za Dynamo Kyjev proti moskevskému armádnímu klubu, čímž zahájil kariéru, jež z něj později udělala jednoho z nejvlivnějších fotbalových trenérů." },
  { country: "ua", year: 1960, category: "Science & tech", text: "Dne 6. listopadu, ve výroční den Říjnové revoluce, otevřelo hlavní město svou první podzemní dráhu, jedinou 5,24 kilometru dlouhou linku o pěti stanicích, jež se stala třetím metrem Sovětského svazu po Moskvě a Leningradu." },
  { country: "ua", year: 1960, category: "Science & tech", text: "Mezi nově otevřenými stanicemi metra byla i Arsenalna, zapuštěná zhruba 105 metrů pod vysokým břehem Dněpru a dostupná pětiminutovou jízdou na eskalátoru, čímž se stala nejhlubší stanicí metra na světě." },
  { country: "ua", year: 1960, category: "Sport", text: "Na olympijských hrách v Římě dovedla gymnastka Larisa Latyninová, rodačka z Chersonu, sovětský ženský tým ke zlatu a obhájila svůj individuální titul ve víceboji na cestě ke kariérní sbírce rekordních osmnácti olympijských medailí." },
  { country: "ua", year: 1960, category: "People", text: "Dne 27. listopadu se v Dněpropetrovsku narodila Julija Tymošenková, budoucí dvojnásobná premiérka a ústřední postava postsovětských politických dramat země." },
  { country: "ua", year: 1961, category: "Sport", text: "Dynamo Kyjev vyhrálo sovětské fotbalové mistrovství nejvyšší soutěže, poprvé kdy nějaký klub mimo Moskvu prolomil hegemonii hlavního města, přičemž specialista na rohové kopy Valerij Lobanovskyj vstřelil z levého křídla deset gólů." },
  { country: "ua", year: 1961, category: "Upheaval", text: "Dne 13. března se po vydatném dešti protrhla hráz zadržující desetiletí tekutého průmyslového odpadu napumpovaného do rokle Babí Jar, čímž vyslala stěnu bahna čtvrtí Kurenivka v hlavním městě a během několika minut zabila až 1500 lidí." },
  { country: "ua", year: 1961, category: "Politics", text: "Volodymyr Ščerbyckyj se stal předsedou Rady ministrů republiky, čímž započal dlouhý vzestup k moci muže, jenž měl ovládat její politiku až do 80. let." },
  { country: "ua", year: 1961, category: "Everyday life", text: "Po celém hlavním městě vyrůstaly levné pětipatrové panelové domy přezdívané „chruščovky“, jejichž stísněné byty s maličkými kuchyněmi a tenkými zdmi nabízely milionům jejich první vlastní rodinné bydlení." },
  { country: "ua", year: 1962, category: "Everyday life", text: "Celostátní oznámení z 31. května, že maso zdraží o 30 procent a máslo o čtvrtinu, vyvolalo nepokoje napříč Sovětským svazem, načež stát na desetiletí zmrazil ceny základních potravin, aby neriskoval další protesty." },
  { country: "ua", year: 1962, category: "Culture", text: "Vasyl Symonenko, přední mladý hlas literární generace šedesátníků, vydal svou debutovou básnickou sbírku „Ticho a hrom“, jež pomohla oživit sebevědomou ukrajinskojazyčnou poezii." },
  { country: "ua", year: 1963, category: "Politics", text: "Petro Šelest, rodák z Charkovské oblasti, převzal vedení Komunistické strany republiky jako vůdce, jenž měl až do svého odvolání v roce 1972 opatrně vyvažovat věrnost Moskvě s tichou obranou národní kultury." },
  { country: "ua", year: 1963, category: "Culture", text: "Cenzoři potlačili sbírku básnířky Liny Kostenkové „Hvězdný integrál“ jako ideologicky škodlivou, čímž zahájili zákaz publikování, který udržel jednu z nejlepších básnířek země v mlčení až do roku 1977." },
  { country: "ua", year: 1963, category: "People", text: "Dne 13. prosince zemřel básník Vasyl Symonenko v Čerkasích pouhých osmadvacetiletý, několik týdnů po brutálním zbití bezpečnostními agenty, a jeho předčasná smrt vzburcovala národní disidentské hnutí." },
  { country: "ua", year: 1963, category: "People", text: "Dne 4. prosince se v Luhansku narodil Serhij Bubka, tyčkař, jenž se měl stát prvním člověkem, který zdolal šest metrů, a pětatřicetkrát překonal světový rekord." },
  { country: "ua", year: 1964, category: "Culture", text: "Sergej Paradžanov natočil ve studiu Dovženka v Kyjevě film „Stíny zapomenutých předků“, zářivý snímek pořízený v huculském nářečí ukrajinštiny v karpatské vesnici Kryvorivňa, jenž se stal mezníkem kinematografie země." },
  { country: "ua", year: 1964, category: "Culture", text: "Výtvarnice Alla Horská a její spolupracovníci vytvořili pro Kyjevskou univerzitu vitráž zobrazující básníka Tarase Ševčenka, jen aby ji viděli odsouzenou jako ideologicky nepřátelskou a zničenou, přičemž umělci byli vyloučeni ze Svazu sovětských umělců." },
  { country: "ua", year: 1964, category: "Sport", text: "Na olympijských hrách v Tokiu získala gymnastka Larisa Latyninová, rodačka z Chersonu, na svých posledních hrách zlato v prostných a v týmové soutěži, čímž završila olympijskou kariéru nevídaného úspěchu." },
  { country: "ua", year: 1965, category: "Science & tech", text: "Dne 27. února uskutečnil letoun Antonov An-22 „Antej“, navržený v Kyjevě a největší turbovrtulové letadlo, jaké kdy bylo postaveno, svůj první let a později ohromil davy na pařížské letecké přehlídce." },
  { country: "ua", year: 1965, category: "Upheaval", text: "Od konce srpna zahájily úřady rozsáhlý zásah proti intelektuálům spjatým s hnutím šedesátníků, čistku, jež zadržela kolem dvou set lidí a udusila kulturní tání." },
  { country: "ua", year: 1965, category: "Culture", text: "Spisovatel Ivan Dzjuba sepsal „Internacionalismus, nebo rusifikace?“, pojednání zaslané stranickým vůdcům, které Leninovými vlastními slovy argumentovalo proti rusifikaci republiky a hojně kolovalo jako podzemní samvydav." },
  { country: "ua", year: 1965, category: "Politics", text: "Kosyginova hospodářská reforma dorazila do republiky, kde obnovila centrální průmyslová ministerstva a zároveň jednotlivým podnikům udělila skromné nové pravomoci nad ziskem a prémiemi v omezené snaze oživit stagnující ekonomiku." },
  { country: "ua", year: 1966, category: "Science & tech", text: "Dne 14. ledna zemřel v Moskvě Sergej Koroljov, konstruktér raket narozený v Žytomyru, který stál za sovětským kosmickým programem a Gagarinovým letem, přičemž jeho totožnost zůstávala pro veřejnost stále státním tajemstvím." },
  { country: "ua", year: 1966, category: "Sport", text: "Dynamo Kyjev, vycvičené v kondici a presinkové taktice trenérem Viktorem Maslovem, vyhrálo sovětské mistrovství i Sovětský pohár, čímž zahájilo sérii tří ligových titulů v řadě až do roku 1968." },
  { country: "ua", year: 1966, category: "Culture", text: "Na sjezdu spisovatelů republiky pronesl stranický šéf Petro Šelest projev, který byl všeobecně chápán jako tiché povzbuzení pro ukrajinskou inteligenci." },
  { country: "ua", year: 1967, category: "Culture", text: "Alla Horská a její kolegové monumentalisté vytvořili pro restauraci v Mariupolu odvážné mozaikové panely, mezi nimi „Strom života“ a „Boryviter“, čímž na její stěny vnesli osobitý národní modernismus." },
  { country: "ua", year: 1968, category: "Upheaval", text: "V dubnu podepsalo 139 kyjevských vědců a kulturních osobností, mezi nimi i výtvarnice Alla Horská, otevřený protestní dopis sovětským vůdcům proti uzavřeným politickým procesům s disidenty." },
  { country: "ua", year: 1969, category: "Science & tech", text: "Obří transportní letoun Antonov An-22 navržený v Kyjevě dorazil do první linie jako první letadlo dodané na sovětskou vojenskou dopravní základnu, čímž dal ozbrojeným silám nepřekonatelného tahouna pro těžké náklady." },
  { country: "ua", year: 1970, category: "Culture", text: "Dne 13. září měla zpěvná píseň „Červona ruta“ od devatenáctiletého skladatele Volodymyra Ivasjuka veřejnou premiéru v živém televizním přenosu z Černovic a brzy se stala neoficiální hymnou národní popové hudby." },
  { country: "ua", year: 1970, category: "Everyday life", text: "Dne 4. února bylo u řeky Pripjať založeno vzorové atomové město Pripjať, jež mělo poskytnout domov dělníkům, kteří měli jednou obsluhovat reaktory rozlehlé nové jaderné elektrárny." },
  { country: "ua", year: 1970, category: "Everyday life", text: "Mladé rodiny obvykle čekaly roky na úředních seznamech na malinký dvoupokojový byt v panelovém domě a stěhování z obecního bytu, který sdílely s ostatními, považovaly za jeden z velkých životních úspěchů, navzdory papírově tenkým stěnám." },
  { country: "ua", year: 1971, category: "Culture", text: "Vizuálně bohaté drama poetického filmu Jurije Iljenka „Bílý pták se znamením černým“, zasazené do huculské karpatské vesnice, získalo Zlatou cenu na Moskevském mezinárodním filmovém festivalu, než bylo úřady Komunistické strany odsouzeno a uloženo do trezoru." },
  { country: "ua", year: 1971, category: "Culture", text: "V podání folkově laděného vokálně-instrumentálního souboru Smeryčka získala píseň „Červona ruta“ na televizním galavečeru v Moskvě titul „Píseň roku“ SSSR." },
  { country: "ua", year: 1972, category: "Politics", text: "Volodymyr Ščerbyckyj, věrný spojenec Leonida Brežněva, nahradil poměrně národnostně smýšlejícího Petra Šelesta ve funkci prvního tajemníka Komunistické strany a měl ovládat republiku až do roku 1989." },
  { country: "ua", year: 1972, category: "Upheaval", text: "Při rozsáhlém lednovém zásahu známém jako „generální pogrom“ zatkla KGB desítky intelektuálů včetně básníka Vasyla Stuse a novináře Vjačeslava Čornovila a toho roku bylo odsouzeno na 89 disidentů." },
  { country: "ua", year: 1972, category: "Sport", text: "Sprinter Valerij Borzov, narozený v Sambiru, vyhrál na olympijských hrách v Mnichově běh na 100 i 200 metrů a zůstává jediným Evropanem, který kdy tento dvojnásobný triumf dokázal." },
  { country: "ua", year: 1973, category: "Politics", text: "Dvouletá čistka vědeckých a kulturních institucí, na niž dohlížel nový šéf ideologie Valentyn Malančuk, přinesla vyloučení z Akademie věd, univerzit, redakčních rad a svazů spisovatelů, výtvarníků a filmařů." },
  { country: "ua", year: 1973, category: "People", text: "Andrij Danylko, později proslulý jako extravagantní drag pódiová persona Verka Serďučka, se narodil 2. října do dělnické rodiny v Poltavě." },
  { country: "ua", year: 1973, category: "Everyday life", text: "Místně vyráběný ZAZ Zaporožec 968A, nejlevnější auto v celém Sovětském svazu, šel do prodeje s takovými moderními prvky, jako byl skládací sloupek řízení a polstrovaná palubní deska." },
  { country: "ua", year: 1973, category: "Sport", text: "Valerij Lobanovskyj převzal vedení fotbalového klubu Dynamo Kyjev a uplatnil datově řízenou, vědecky podloženou tréninkovou metodu vyvinutou s badatelem Anatolijem Zelencovem, jež kladla důraz na neúnavný presink." },
  { country: "ua", year: 1974, category: "Sport", text: "V Lobanovského první kompletní sezoně získalo Dynamo Kyjev sovětský ligový i pohárový double, přičemž útočník Oleh Blochin skončil nejlepším střelcem ligy a byl vyhlášen sovětským fotbalistou roku." },
  { country: "ua", year: 1974, category: "Politics", text: "Dva roky po vlně zatýkání známé jako „generální pogrom“ skomírala celá generace spisovatelů a aktivistů národa, mezi nimi básníci Vasyl Stus a Ihor Kalynec a literární kritik Ivan Svitlyčnyj, v dalekých pracovních táborech, zatímco stranický šéf Volodymyr Ščerbyckyj prosazoval své tažení za rusifikací škol a univerzit." },
  { country: "ua", year: 1975, category: "Sport", text: "Dynamo Kyjev porazilo 14. května v Basileji maďarský Ferencváros 3:0 a získalo Pohár vítězů pohárů, čímž se stalo vůbec prvním sovětským klubem, který vyhrál velkou evropskou trofej." },
  { country: "ua", year: 1975, category: "Sport", text: "Útočník Oleh Blochin se trefil v obou zápasech, když Dynamo Kyjev porazilo v součtu Bayern Mnichov 3:0 a získalo Superpohár UEFA, a v prosinci převzal Zlatý míč jako nejlepší evropský fotbalista." },
  { country: "ua", year: 1975, category: "Everyday life", text: "Dne 23. srpna otevřel Charkov první osmistaniční úsek svého nového metra, čímž se stal teprve šestým městem v SSSR a druhým v republice, které získalo podzemní dráhu." },
  { country: "ua", year: 1975, category: "People", text: "Herečka a modelka Milla Jovovichová, později hollywoodská hvězda, se narodila 17. prosince v Kyjevě." },
  { country: "ua", year: 1976, category: "Politics", text: "Dne 9. listopadu založilo v Kyjevě deset aktivistů, mezi nimi spisovatel Mykola Rudenko, Ukrajinskou helsinskou skupinu, aby sledovala, jak Sověti dodržují lidskoprávní závazky z helsinských dohod." },
  { country: "ua", year: 1976, category: "People", text: "Andrij Ševčenko, který se měl stát největším fotbalistou národa a držitelem Zlatého míče, se narodil 29. září ve vesnici Dvirkivščyna." },
  { country: "ua", year: 1977, category: "Science & tech", text: "Dne 26. září byl spuštěn první reaktorový blok černobylské jaderné elektrárny, úvodní článek budoucího komplexu o čtyřech reaktorech a první jaderná elektrárna na půdě republiky." },
  { country: "ua", year: 1977, category: "Science & tech", text: "Dne 31. srpna se poprvé vznesl Antonov An-72, vůbec první proudový transportní letoun konstrukční kanceláře, přezdívaný Čeburaška pro sání motorů umístěná nad křídly." },
  { country: "ua", year: 1978, category: "Politics", text: "Nové usnesení zesílilo výuku ruštiny už od nejnižších ročníků ve školách republiky, čímž prohloubilo trvalý úpadek rodného jazyka za Ščerbyckého vlády." },
  { country: "ua", year: 1978, category: "Everyday life", text: "Poté co hubené sklizně z počátku desetiletí donutily zemi dovážet obilí, přinesla pole rekordní úrodu, jež odrážela roli republiky coby zemědělského srdce Sovětského svazu." },
  { country: "ua", year: 1979, category: "Culture", text: "Tělo milovaného skladatele Volodymyra Ivasjuka, autora písně „Červona ruta“, bylo v květnu nalezeno oběšené v lese poblíž Lvova, několik týdnů poté, co zmizel; oficiálnímu verdiktu o sebevraždě málokdo věřil a smrt bývá často kladena za vinu KGB." },
  { country: "ua", year: 1980, category: "Sport", text: "Když Spojené státy a desítky spojenců bojkotovaly moskevskou letní olympiádu kvůli invazi do Afghánistánu, odehrály se úvodní fotbalové zápasy přesto před diváky na stotisícovém Republikovém stadionu v hlavním městě." },
  { country: "ua", year: 1980, category: "Sport", text: "Gymnastka Stella Zacharovová, rodačka z Oděsy, pomohla sovětskému ženskému týmu ke zlatu a oslnila rozhodčí jako první žena, která v prostných předvedla tři dvojná salta vzad." },
  { country: "ua", year: 1980, category: "Everyday life", text: "V republice proslulé úrodnou černozemí stáli nakupující stejně hodiny ve frontách a spoléhali na osobní známosti, takzvanou síť „blatu“, aby sehnali uzeninu, rybu či pomeranče, zatímco straničtí funkcionáři si dopřávali kraby, kaviár a švýcarský sýr." },
  { country: "ua", year: 1980, category: "Culture", text: "Sopranistka Kvitka Cisyková, narozená v Americe, vydala své první album ukrajinských písní „Kvitka, Songs of Ukraine“, jímž s láskou uchovala lidový repertoár v zahraničí ve chvíli, kdy byl doma potlačován." },
  { country: "ua", year: 1980, category: "Politics", text: "Zkušený disident a člen Helsinské skupiny Vjačeslav Čornovil byl opět zatčen, tentokrát na základě vykonstruovaných obvinění, zatímco pokračovalo tvrdé rusifikační tažení stranického šéfa Volodymyra Ščerbyckého." },
  { country: "ua", year: 1981, category: "Culture", text: "Dne 9. května odhalil Leonid Brežněv v hlavním městě vysoko nad Dněprem pomník Vlasti-matky, dvaašedesát metrů vysokou ženu z nerezové oceli pozvedající meč a štít na vrcholu rozlehlého nového muzea Velké vlastenecké války." },
  { country: "ua", year: 1981, category: "Sport", text: "Dynamo Kyjev se podesáté stalo sovětským mistrem, čímž kyjevský klub i hrozen ukrajinských hvězd v jeho jádru potvrdily své postavení dominantní síly celosvazového fotbalu." },
  { country: "ua", year: 1981, category: "Politics", text: "Většina zakladatelů Ukrajinské helsinské skupiny, založené v roce 1976, aby sledovala, jak Moskva dodržuje lidskoprávní závazky z helsinských dohod, byla do té doby zlomena a poslána do táborů, mezi nimi spisovatel a zakladatel Mykola Rudenko i zkušená aktivistka Oksana Meškoová." },
  { country: "ua", year: 1982, category: "Science & tech", text: "Dne 24. prosince se z letiště Svjatošyn v hlavním městě poprvé vznesl Antonov An-124 Ruslan, tehdy největší transportní letoun na světě, schopný uvézt 150 tun nákladu." },
  { country: "ua", year: 1983, category: "Culture", text: "Cenzoři tak silně zmrzačili film Kiry Muratovové „Mezi šedými kameny“, že se k němu oděská režisérka odmítla hlásit a na protest stáhla své jméno z titulků." },
  { country: "ua", year: 1984, category: "Sport", text: "Doněcký tyčkař Serhij Bubka vytvořil první ze svých mnoha světových rekordů, když v květnu zdolal 5,85 metru a zahájil vládu, jež měla tuto disciplínu zcela proměnit." },
  { country: "ua", year: 1984, category: "People", text: "Kardinál Josyf Slipyj, který přežil téměř dvě desetiletí v sovětských pracovních táborech, zemřel v Římě, kam osobně přišel papež Jan Pavel II. uctít vůdce zakázané, do katakomb zahnané řeckokatolické církve." },
  { country: "ua", year: 1985, category: "Sport", text: "Dne 13. července se v Paříži stal Serhij Bubka prvním člověkem, který skočil o tyči přes šest metrů, a sklidil bouřlivé ovace ve stoje poté, co téhož rána přiletěl z Moskvy." },
  { country: "ua", year: 1985, category: "Everyday life", text: "Gorbačovova nová protialkoholní kampaň tvrdě dolehla na jižní republiku, neboť zhruba třetina krymských vinic byla vyklučena a vzácné odrůdy révy nenávratně zmizely." },
  { country: "ua", year: 1986, category: "Upheaval", text: "V 1:23 ráno dne 26. dubna vybuchl reaktor č. 4 černobylské elektrárny u Pripjati během zpackaného bezpečnostního testu a vymrštil do vzduchu přes padesát tun radioaktivního materiálu, čímž způsobil nejhorší jadernou havárii v dějinách." },
  { country: "ua", year: 1986, category: "Upheaval", text: "Den po výbuchu byla zhruba devětačtyřicet tisíc obyvatel Pripjati evakuováno dlouhou kolonou autobusů a opustilo zbrusu nové město, které se proměnilo ve strnulé město duchů." },
  { country: "ua", year: 1986, category: "Politics", text: "Přestože nad hlavní město zavanula radiace, úřady uspořádaly prvomájový průvod na Chreščatyku a Ščerbyckij dostal příkaz pochodovat jím s vlastními vnoučaty." },
  { country: "ua", year: 1986, category: "Sport", text: "Dynamo Kyjev vedené Valerijem Lobanovským rozdrtilo 2. května v Lyonu Atlético Madrid 3:0 a získalo Pohár vítězů pohárů, když se trefili Zavarov, Blochin a Jevtušenko." },
  { country: "ua", year: 1986, category: "Sport", text: "Útočník Dynama Kyjev Ihor Belanov byl vyhlášen evropským fotbalistou roku a získal Zlatý míč po sezoně korunované hattrickem proti Belgii na mistrovství světa v Mexiku." },
  { country: "ua", year: 1986, category: "Science & tech", text: "Asi 200 000 „likvidátorů“ z celého Sovětského svazu se po celý rok dřelo, aby zasypali trosky a uzavřeli zničený reaktor do rozlehlého betonového sarkofágu, dokončeného koncem listopadu." },
  { country: "ua", year: 1987, category: "Politics", text: "Od 7. do 30. července soudil tribunál zasedající v domě kultury evakuovaného města Černobyl muže obviněné z katastrofy a odsoudil ředitele elektrárny Viktora Brjuchanova, hlavního inženýra Nikolaje Fomina i jeho zástupce Anatolije Ďatlova shodně k deseti letům v pracovním táboře, a to v procesu inscenovaném jako výkladní skříň Gorbačovovy nové otevřenosti." },
  { country: "ua", year: 1987, category: "Politics", text: "Jak glasnosť uvolnila sevření režimu, sešli se 8. června disidenti v jedné kyjevské kavárně a založili Ukrajinský kulturologický klub, první otevřeně nezávislé občanské sdružení v republice po desetiletích." },
  { country: "ua", year: 1987, category: "Culture", text: "Ve Lvově založili 19. října mladí aktivisté Společnost lva, studenty vedenou skupinu věnovanou oživení ukrajinského jazyka, dějin a dědictví, jež měla pomoci roztočit národní obrození nadcházejících let." },
  { country: "ua", year: 1988, category: "Politics", text: "Díky Gorbačovově amnestii pro politické vězně oživili propuštění disidenti v čele s Vjačeslavem Čornovilem lidskoprávní hnutí založením Ukrajinského helsinského svazu." },
  { country: "ua", year: 1989, category: "Upheaval", text: "V červenci složilo půl milionu havířů na Donbasu a po celém SSSR nářadí a ve vlně stávek, často označované za jiskru ukrajinské revoluce let 1989–1991, si vymohlo ústupky ohledně jídla, mýdla a bydlení." },
  { country: "ua", year: 1989, category: "Politics", text: "Ve dnech 8.–10. září uspořádalo Lidové hnutí Ukrajiny Ruch svůj ustavující sjezd s básníkem Ivanem Dračem jako prvním vůdcem a rychle se stalo masovou silou demokratické a národní obrody." },
  { country: "ua", year: 1989, category: "Politics", text: "Uprostřed sílících protestů osobně zasáhl Gorbačov a sesadil dlouhosloužícího zastánce tvrdé linie Volodymyra Ščerbyckého z čela Komunistické strany, čímž ukončil éru rusifikace a neostalinské vlády." },
  { country: "ua", year: 1989, category: "Culture", text: "Dne 28. října přijal Nejvyšší sovět republiky jazykový zákon, jímž po desetiletích plíživé rusifikace prohlásil ukrajinštinu za státní jazyk." },
  { country: "ua", year: 1989, category: "People", text: "V předvečer Gorbačovova setkání s papežem Janem Pavlem II. konečně sovětská vláda dovolila zakázané řeckokatolické církvi vynořit se po čtyřech desetiletích z ilegality a znovu zaregistrovat své farnosti." },
  { country: "ua", year: 1989, category: "Culture", text: "Ponuré, roztříštěné veledílo Kiry Muratovové „Astenický syndrom“ zachytilo vyčerpání pozdního sovětského života a navzdory letům cenzury její tvorby získalo Stříbrného medvěda v Berlíně." },
  { country: "ua", year: 1990, category: "Upheaval", text: "Dne 21. ledna se přes 300 000 lidí chytilo za ruce do zhruba 480 kilometrů dlouhého lidského řetězu táhnoucího se ze Lvova a Ivano-Frankivsku až do hlavního města, čímž po vzoru Baltské cesty žádali jednotu a pokojné odtržení od Sovětského svazu." },
  { country: "ua", year: 1990, category: "Politics", text: "Dne 16. července přijal parlament v Kyjevě poměrem 355 ku 4 Deklaraci o státní svrchovanosti, jíž prohlásil, že republikové právo má přednost před sovětským a že si republika ponechá vlastní armádu, centrální banku a měnu." },
  { country: "ua", year: 1990, category: "Upheaval", text: "V říjnu postavily stovky studentů na hlavním náměstí hlavního města stany a zahájily hladovku v rámci „revoluce na žule“, čímž po šestnácti dnech vynutily rezignaci premiéra." },
  { country: "ua", year: 1990, category: "Everyday life", text: "Jak se sovětské direktivní hospodářství rozpadalo, začala republika vydávat vedle téměř bezcenných rublů poukázky, aby si obyvatelé mohli uprostřed sílícího nedostatku a front koupit potraviny a základní zboží." },
  { country: "ua", year: 1991, category: "Culture", text: "Druhý ročník festivalu ukrajinskojazyčné hudby Červona ruta byl záměrně uspořádán v silně rusifikovaném Záporoží, kde představil kapely jako budoucí Skrjabin a dal východnímu publiku okusit možnou samostatnou národní kulturu." },
  { country: "ua", year: 1991, category: "Politics", text: "Dne 24. srpna vyhlásil parlament plnou nezávislost, rozhodnutí, které pak v prosincovém referendu předložil ke schválení lidu." },
  { country: "ua", year: 1991, category: "Upheaval", text: "Dne 11. října vzplála po elektrickém přepětí turbína v reaktoru č. 2 černobylské elektrárny, což vedlo k trvalému odstavení tohoto bloku." },
  { country: "ua", year: 1991, category: "Politics", text: "Dne 1. prosince přišlo k urnám zhruba 84 procent voličů a asi 92 procent z nich podpořilo nezávislost; téhož dne byl prvním prezidentem zvolen Leonid Kravčuk." },
  { country: "ua", year: 1991, category: "Science & tech", text: "Když se v prosinci rozpadal Sovětský svaz, stal se Antonov An-225 Mrija, nejtěžší letoun, jaký kdy byl postaven a původně navržený k převozu raketoplánu Buran, národním pokladem, než byl pro nedostatek peněz odstaven." },
  { country: "ua", year: 1992, category: "Everyday life", text: "Dne 10. ledna nahradila karbovaněcová poukázka v poměru jedna ku jedné rubl coby běžné platidlo, přestože pulty obchodů zůstávaly prázdné, víkendová tržiště vzkvétala a nová měna soustavně ztrácela hodnotu." },
  { country: "ua", year: 1992, category: "Politics", text: "Spor s Ruskem o bývalou sovětskou Černomořskou flotilu a práva na základnu v Sevastopolu přerostl v dubnu v otevřené soupeření, když Boris Jelcin a Leonid Kravčuk vydali navzájem si odporující výnosy, jimiž si flotilu každý nárokoval." },
  { country: "ua", year: 1993, category: "Everyday life", text: "Hyperinflace se zcela vymkla kontrole a dosáhla roční míry přes 4 700 procent, karbovaněc se zhroutil vůči dolaru a minimální mzda měla hodnotu sotva pár dolarů měsíčně." },
  { country: "ua", year: 1993, category: "Sport", text: "V únoru vytvořil tyčkař Serhij Bubka, vůbec první člověk, který zdolal šest metrů, poslední ze svých světových rekordů v hale ve svém rodném Doněcku." },
  { country: "ua", year: 1993, category: "Upheaval", text: "V červnu rozpoutal prudký skok cen základních potravin havířskou stávku po celém Donbasu, jíž se zúčastnily statisíce dělníků a která byla největším jednotlivým protestem, jaký mladý stát zažil." },
  { country: "ua", year: 1994, category: "Politics", text: "Předčasné prezidentské volby v červnu a červenci přinesly první pokojné předání moci v rámci bývalého Sovětského svazu, když Leonid Kučma porazil úřadujícího Kravčuka, jenž porážku přijal." },
  { country: "ua", year: 1994, category: "Upheaval", text: "Na Krymu byl proruský Jurij Meškov zvolen prezidentem poloostrova na separatistickém programu s téměř 73 procenty hlasů, čímž rozpoutal pat s Kyjevem." },
  { country: "ua", year: 1994, category: "Politics", text: "Dne 5. prosince bylo podepsáno Budapešťské memorandum, jímž země přistoupila na to, že se vzdá třetího největšího jaderného arzenálu na světě výměnou za bezpečnostní záruky od Ruska, Spojených států a Británie." },
  { country: "ua", year: 1994, category: "People", text: "Dne 12. září se v Oděse narodila budoucí tenisová hvězda Elina Svitolinová, jež se měla stát nejvýše postavenou Ukrajinkou v historii žebříčku." },
  { country: "ua", year: 1995, category: "Politics", text: "Parlament odpověděl na krymskou separatistickou krizi zrušením ústavy poloostrova a zánikem jeho prezidentského úřadu, čímž odsunul a poslal do exilu nedošlého vůdce odtržení." },
  { country: "ua", year: 1996, category: "Politics", text: "Dne 28. června přijal parlament po celonočním jednání první postsovětskou ústavu země, která potvrdila ukrajinštinu jako jediný státní jazyk." },
  { country: "ua", year: 1996, category: "Sport", text: "Na olympijských hrách v Atlantě, prvních pro zemi coby samostatný stát, získala gymnastka Lilija Podkopajevová tituly ve víceboji i v prostných, zatímco dospívající boxer Volodymyr Kličko vybojoval zlato v supertěžké váze." },
  { country: "ua", year: 1996, category: "Everyday life", text: "Při měnové reformě probíhající od 2. do 16. září byl hyperinflovaný karbovaněc vyměněn za novou hřivnu v poměru 100 000 ku 1, což byla stabilizace, jež nastartovala politickou kariéru bankéře centrální banky Viktora Juščenka." },
  { country: "ua", year: 1996, category: "Upheaval", text: "Dne 30. listopadu byl pod tlakem zahraničních vlád odstaven reaktor č. 1 černobylské elektrárny, jak země směřovala zasažené místo k uzavření." },
  { country: "ua", year: 1997, category: "Politics", text: "Dne 28. května podepsali premiéři obou zemí dohodu o rozdělení bývalé sovětské Černomořské flotily, přičemž Rusko si vzalo větší podíl a pronajalo si v Sevastopolu námořní zařízení." },
  { country: "ua", year: 1997, category: "Culture", text: "Skupina Vopli Vidopljasova, průkopníci zpívaného rocku v ukrajinštině namísto ruštiny, vydala hit „Vesna“ („Jaro“), který se stal jednou z nejmilovanějších hymen obrody té doby." },
  { country: "ua", year: 1997, category: "Science & tech", text: "Dne 19. listopadu vzlétl Leonid Kaďenjuk na palubě amerického raketoplánu Columbia jako odborník na užitečné zatížení, čímž se stal prvním kosmonautem samostatného státu, a na oběžné dráze prováděl experimenty s růstem rostlin." },
  { country: "ua", year: 1998, category: "Sport", text: "Andrij Ševčenko, který v roce 1994 debutoval za Dynamo Kyjev jako osmnáctiletý, pomáhal pohánět obrození klubu pod trenérem Valerijem Lobanovským k evropské špičce." },
  { country: "ua", year: 1999, category: "Politics", text: "Dne 21. ledna vyhlásil prezident Kučma výnosem nový státní svátek, Den jednoty, slavený každého 22. ledna na památku aktu z roku 1919, jenž sjednotil východní a západní ukrajinskou republiku." },
  { country: "ua", year: 1999, category: "Sport", text: "Dne 7. dubna remizovalo Dynamo Kyjev 3:3 s Bayernem Mnichov, přičemž Ševčenko se trefil dvakrát, ve vůbec prvním semifinále Ligy mistrů v historii klubu." },
  { country: "ua", year: 2000, category: "Politics", text: "Opoziční novinář Heorhij Gongadze, spoluzakladatel investigativního webu Ukrajinska pravda, byl v září unesen a později nalezen sťatý v lese za hlavním městem, čímž rozpoutal politické zemětřesení." },
  { country: "ua", year: 2000, category: "Upheaval", text: "V listopadu pustil socialistický poslanec tajně pořízené nahrávky, na nichž prezident zdánlivě nařizoval odstranění novináře, čímž odstartoval „kazetový skandál“ a protestní hnutí „Ukrajina bez Kučmy“." },
  { country: "ua", year: 2000, category: "Sport", text: "Plavkyně Jana Kločkovová, přezdívaná „královna polohovky“, získala na hrách v Sydney dvě olympijská zlata a vytvořila světový rekord v polohovém závodě na 400 metrů." },
  { country: "ua", year: 2001, category: "Everyday life", text: "První a jediné sčítání lidu po vyhlášení nezávislosti napočítalo něco přes 48 milionů obyvatel, o více než tři miliony méně než pozdně sovětský součet o dvanáct let dříve." },
  { country: "ua", year: 2001, category: "People", text: "Mychajlo Mudryk, který měl vyrůst v nejdráže prodaného fotbalistu země při rekordním přestupu do Chelsea, se narodil 5. ledna v Charkovské oblasti." },
  { country: "ua", year: 2002, category: "Upheaval", text: "Dne 27. července se na letecké přehlídce poblíž Lvova zřítila stíhačka Su-27 mezi diváky, zabila 77 lidí a stovky dalších zranila v dosud nejtragičtější havárii leteckého dne v dějinách." },
  { country: "ua", year: 2003, category: "Culture", text: "Folklorní kozácké drama Olese Sanina „Mamaj“, natočené za pouhých 24 dní, se stalo teprve druhým filmem, který kdy země přihlásila do soutěže o Oscara za nejlepší cizojazyčný film." },
  { country: "ua", year: 2003, category: "Sport", text: "Těžkotonážní Vitalij Kličko prohrál s Lennoxem Lewisem jen proto, že zápas byl zastaven kvůli ošklivé tržné ráně, ačkoli vedl na všech třech bodovacích lístcích, čímž si připravil cestu k zisku titulu mistra světa o rok později." },
  { country: "ua", year: 2004, category: "Culture", text: "Zpěvačka Ruslana dovedla zemi k vítězství na Eurovizi v Istanbulu kožemi obalenou, bubny hnanou písní „Wild Dances“, když získala 280 bodů a vůbec první korunu pro zemi." },
  { country: "ua", year: 2004, category: "Sport", text: "Útočník AC Milán Andrij Ševčenko převzal Zlatý míč a stal se třetím fotbalistou ze země, který získal nejvyšší evropské individuální ocenění, po Olehu Blochinovi a Ihoru Belanovovi." },
  { country: "ua", year: 2004, category: "People", text: "Opoziční prezidentský kandidát Viktor Juščenko byl na zářijové večeři otráven čistým dioxinem a jeho tvář zůstala zohyzděná chlorakné poté, co jeho krev vykázala hladiny asi padesátitisíckrát vyšší než normální." },
  { country: "ua", year: 2004, category: "Upheaval", text: "Po volebním kole pošpiněném podvody tábořily statisíce lidí v oranžovém na hlavním náměstí v krutém mrazu během oranžové revoluce, dokud nejvyšší soud výsledek nezrušil." },
  { country: "ua", year: 2004, category: "Politics", text: "V opakovaném druhém kole prezidentské volby nařízeném soudem na 26. prosince byl s asi 52 procenty hlasů zvolen Viktor Juščenko, čímž zvrátil sporný oficiální výsledek." },
  { country: "ua", year: 2005, category: "Politics", text: "Juščenko složil 23. ledna prezidentský slib před obrovským davem, čímž formálně uzavřel oranžovou revoluci a uvedl do úřadu prozápadní vládu." },
  { country: "ua", year: 2006, category: "Upheaval", text: "Na Nový rok začal Gazprom omezovat plyn proudící přes zemi, čímž nakrátko snížil tlak v plynovodech po celé Evropě, než o pár dní později dohoda obnovila dodávky." },
  { country: "ua", year: 2006, category: "Sport", text: "Při své vůbec první účasti na mistrovství světa porazil národní fotbalový tým Švýcarsko na penalty, aniž inkasoval jediný pokutový kop, a postoupil do čtvrtfinále v Německu." },
  { country: "ua", year: 2006, category: "Culture", text: "Vládní výnos začal v kinech postupně zavádět povinný dabing zahraničních filmů do ukrajinštiny, sporný kulturní obrat vítaný na západě a zazlívaný v rusky mluvících městech." },
  { country: "ua", year: 2006, category: "Politics", text: "Dne 28. listopadu schválil parlament zákon, který formálně prohlásil hladomor z let 1932–1933, holodomor, za genocidu spáchanou na ukrajinském lidu." },
  { country: "ua", year: 2007, category: "Culture", text: "Komik Andrij Danylko, vystupující ve své blyštivé drag personě Verka Serďučka, skončil na Eurovizi na památném druhém místě s vícejazyčným rejdivým hitem „Dancing Lasha Tumbai“." },
  { country: "ua", year: 2007, category: "Everyday life", text: "Zatímco sedm let nepřetržitého růstu kolem sedmi procent živilo novou městskou střední třídu, lvovská rocková kapela Okean Elzy byla korunována nejlepší koncertní kapelou postsovětského prostoru." },
  { country: "ua", year: 2008, category: "Politics", text: "Dne 16. května se země stala 152. členem Světové obchodní organizace, čímž završila téměř patnáct let přístupových jednání." },
  { country: "ua", year: 2008, category: "Politics", text: "Na dubnovém summitu v Bukurešti NATO prohlásilo, že se země jednoho dne stane členem, avšak pod francouzským a německým tlakem jí odepřelo Akční plán členství, o nějž usilovala." },
  { country: "ua", year: 2008, category: "Everyday life", text: "Globální finanční krize ke konci roku tvrdě zasáhla hospodářství závislé na vývozu oceli, srazila hřivnu vůči dolaru a donutila zemi přijmout nouzový úvěr od MMF." },
  { country: "ua", year: 2009, category: "Upheaval", text: "Novoroční plynový spor přerostl ve třináctidenní zastavení veškerého ruského plynu proudícího přes zemi, takže domácnosti v jihovýchodní Evropě zůstaly uprostřed zimy bez tepla, dokud Putin a Tymošenková neuzavřeli desetiletou dohodu." },
  { country: "ua", year: 2009, category: "Politics", text: "Bývalý generál ministerstva vnitra Oleksij Pukač byl zatčen za vraždu novináře Heorhije Gongadzeho z roku 2000 a podle zpráv se ke své roli přiznal téměř deset let po činu." },
  { country: "ua", year: 2010, category: "Politics", text: "Po těsném druhém kole porazil v únorové prezidentské volbě Viktor Janukovyč jen o vlas premiérku Juliji Tymošenkovou, čímž zvrátil výsledek oranžové revoluce z roku 2004 a naklonil zemi zpět k Moskvě." },
  { country: "ua", year: 2010, category: "Politics", text: "V dubnu podepsali prezident Janukovyč a ruský Dmitrij Medveděv Charkovské dohody, jimiž prodloužili pronájem základny Černomořské flotily v Sevastopolu do roku 2042 výměnou za třicetiprocentní slevu na ruský zemní plyn." },
  { country: "ua", year: 2011, category: "Sport", text: "Bratři Vitalij a Volodymyr Kličkové se zapsali do Guinnessovy knihy rekordů jako sourozenci s nejvíce vítězstvími v zápasech o titul mistra světa v těžké váze, neboť tuto váhovou kategorii boxu ovládali ve dvojici." },
  { country: "ua", year: 2011, category: "People", text: "Bývalá premiérka Julija Tymošenková, hrdinka oranžové revoluce se svým pověstným copem, byla odsouzena k sedmi letům vězení za plynovou dohodu s Ruskem, v procesu v zahraničí všeobecně odsouzeném jako politicky motivovaný." },
  { country: "ua", year: 2012, category: "Sport", text: "Společně s Polskem byla země spolupořadatelem mistrovství Evropy ve fotbale, jehož finále se hrálo na kyjevském Olympijském stadionu, kde Španělsko porazilo Itálii 4:0." },
  { country: "ua", year: 2012, category: "People", text: "Na Euru 2012 vstřelil zkušený kapitán Andrij Ševčenko v úvodním zápase dvě hlavičky a porazil Švédsko 2:1, ve svém posledním velkém vzepětí, než ukončil kariéru jako historicky nejlepší střelec země se 48 reprezentačními góly." },
  { country: "ua", year: 2012, category: "Culture", text: "Elektrofolkovou kapelu ONUKA založili Nata Žyžčenková a Jevhen Filatov, kteří mísili tradiční nástroje jako banduru a sopilku s pulzujícími elektronickými aranžemi." },
  { country: "ua", year: 2013, category: "Upheaval", text: "Když prezident v listopadu náhle odmítl podepsat asociační dohodu s Evropskou unií, shromáždili se studenti na kyjevském náměstí Nezávislosti, čímž zažehli několik měsíců trvající protesty Euromajdanu." },
  { country: "ua", year: 2013, category: "Everyday life", text: "Jednoho chladného prosincového večera strhli demonstranti žulovou sochu Lenina na kyjevském Besarabském náměstí a spustili tak vlnu bourání pomníků přezdívanou „leninopad“, tedy „pád Leninů“." },
  { country: "ua", year: 2014, category: "Upheaval", text: "Dne 20. února, v nejkrvavější den povstání, stříleli odstřelovači do demonstrantů v centru Kyjeva a zhruba sto protestujících zabitých během revoluce začalo být uctíváno jako „nebeská setnina“." },
  { country: "ua", year: 2014, category: "Politics", text: "Poté co prezident Janukovyč koncem února uprchl ze země, odhlasoval parlament poměrem 328 ku nule jeho odvolání z úřadu a vyhlášení nových voleb, čímž ukončil jeho vládu." },
  { country: "ua", year: 2014, category: "Upheaval", text: "Od konce února do března obsadili Krym neoznačení ruští vojáci přezdívaní „zelení mužíčci“ a Moskva poloostrov po referendu, které neuznala téměř žádná jiná země, formálně anektovala." },
  { country: "ua", year: 2014, category: "Upheaval", text: "Dne 17. července sestřelila raketa Buk ruské výroby nad válkou rozervaným Donbasem let Malaysia Airlines 17 a zabila všech 298 lidí na palubě letu z Amsterodamu do Kuala Lumpuru." },
  { country: "ua", year: 2014, category: "Everyday life", text: "Měna se zřítila do volného pádu poté, co ji centrální banka nechala plovat, a hřivna nakonec ztratila vůči dolaru zhruba sedmdesát procent své hodnoty, zatímco ceny běžného zboží prudce stoupaly." },
  { country: "ua", year: 2014, category: "Politics", text: "Cukrovinkový magnát Petro Porošenko, přezdívaný pro svou značku Roshen „čokoládový král“, byl v květnu zvolen prezidentem ve chvíli, kdy se země zmítala po revoluci a ztrátě Krymu." },
  { country: "ua", year: 2015, category: "Upheaval", text: "V lednu byli obklíčení „kyborgové“, kteří 242 dní bránili doněcké mezinárodní letiště, nakonec přemoženi silami podporovanými Ruskem." },
  { country: "ua", year: 2015, category: "Politics", text: "V únoru podepsali vůdci sešlí se v Bělorusku dohodu Minsk II, křehkou dohodu o příměří uzavřenou právě ve chvíli, kdy byly ukrajinské jednotky vytlačovány ze železničního uzlu Debalceve." },
  { country: "ua", year: 2015, category: "Everyday life", text: "Do poloviny roku vyhnala válka na východě a ztráta Krymu z domovů přes 1,3 milionu lidí uvnitř země, kteří se tísnili v pronajatých pokojích a útulcích ve městech jako Charkov a Kyjev." },
  { country: "ua", year: 2015, category: "Politics", text: "Prezident Porošenko podepsal v květnu dekomunizační zákony, jež zakázaly sovětské symboly a spustily hromadné přejmenovávání desítek tisíc ulic a desítek měst pojmenovaných po komunistických osobnostech." },
  { country: "ua", year: 2015, category: "People", text: "Ruský soud odsoudil krymského filmaře Oleha Sencova k dvaceti letům vězení na základě vykonstruovaných obvinění z terorismu a on po vynesení rozsudku vzdorně zazpíval státní hymnu." },
  { country: "ua", year: 2016, category: "Culture", text: "Zpěvačka Jamala vyhrála Eurovizi s písní „1944“, naléhavou skladbou zčásti v krymskotatarštině o deportaci jejího národa za Stalinovy éry, když získala rekordních 534 bodů." },
  { country: "ua", year: 2016, category: "Sport", text: "Gymnasta Oleh Vernjajev získal na olympijských hrách v Riu zlato na bradlech a stříbro ve víceboji, čímž vybojoval první olympijskou medaili země v gymnastickém víceboji od roku 2000." },
  { country: "ua", year: 2016, category: "Science & tech", text: "V listopadu nasunuli inženýři přes zničený černobylský reaktor kolosální oblouk Nového bezpečného krytu o hmotnosti 36 000 tun, čímž dokončili jednu z největších pohyblivých konstrukcí, jaké kdy byly postaveny." },
  { country: "ua", year: 2016, category: "Science & tech", text: "Průhledný elektronický systém zadávání veřejných zakázek ProZorro, zrozený z dobrovolnického protikorupčního projektu, se stal povinným pro státní nákupy a získal toho roku cenu World Procurement Award." },
  { country: "ua", year: 2017, category: "Everyday life", text: "Od 11. června mohli držitelé biometrických pasů cestovat bez víz do schengenského prostoru Evropské unie na krátké pobyty, čímž se naplnil jeden z klíčových slibů Euromajdanu." },
  { country: "ua", year: 2017, category: "Culture", text: "Válečné drama „Kyborgové: Hrdinové neumírají“ mělo premiéru ve třetí výročí pádu letiště, jako součást vlny domácí kinematografie zpracovávající konflikt na východě." },
  { country: "ua", year: 2018, category: "Politics", text: "Dne 15. prosince sloučil sjednocovací sněm ve starobylém kyjevském chrámu sv. Sofie soupeřící pravoslavné jurisdikce země v jedinou samostatnou Pravoslavnou církev Ukrajiny a zvolil jejím představeným devětatřicetiletého metropolitu Epifanije, čímž došlo k historickému rozchodu se staletími církevní podřízenosti Moskvě." },
  { country: "ua", year: 2018, category: "Upheaval", text: "Dne 25. listopadu narazila plavidla ruské pobřežní stráže do tří člunů ukrajinského námořnictva, zahájila na ně palbu a zajala je i s jejich čtyřiadvaceti členy posádky u pobřeží okupovaného Krymu v Kerčském průlivu, načež prezident Petro Porošenko vyhlásil v pohraničních a pobřežních oblastech země stanné právo." },
  { country: "ua", year: 2018, category: "Sport", text: "Dne 26. května hostil Olympijský stadion v hlavním městě finále Ligy mistrů, kde Real Madrid porazil Liverpool 3:1 a před celosvětovým televizním publikem pozvedl nejcennější trofej evropského klubového fotbalu třetí rok v řadě." },
  { country: "ua", year: 2019, category: "Culture", text: "Dne 6. ledna předal v Istanbulu ekumenický patriarcha Bartoloměj metropolitovi Epifanijovi „tomos“, dekret udělující nově sjednocené pravoslavné církvi nezávislost na Moskvě." },
  { country: "ua", year: 2019, category: "Politics", text: "Komik Volodymyr Zelenskyj, který hrál smyšleného prezidenta v úspěšném televizním seriálu „Sluha národa“, vyhrál skutečné prezidentství drtivým vítězstvím s asi 73 procenty hlasů ve druhém kole." },
  { country: "ua", year: 2019, category: "Science & tech", text: "Nový bezpečný kryt nad zničeným černobylským reaktorem prošel v dubnu závěrečnými kolaudačními zkouškami a později byl formálně předán státu, čímž bylo místo zapečetěno na celé století." },
  { country: "ua", year: 2019, category: "People", text: "V září vyšel filmař Oleh Sencov konečně na svobodu, propuštěn za hrdinského přivítání v rámci velké výměny vězňů mezi Ruskem a Ukrajinou." },
  { country: "ua", year: 2020, category: "Upheaval", text: "Dne 8. ledna sestřelily dvě íránské rakety pár minut po startu z Teheránu dopravní letadlo mířící do Kyjeva a zabily všech 176 lidí na palubě, z nichž mnozí byli studenti a rodiny cestující domů přes Kanadu." },
  { country: "ua", year: 2020, category: "Science & tech", text: "V únoru stát spustil aplikaci pro chytré telefony zvanou Dija, která sdružovala státní služby na jednom místě, a během roku se země stala první na světě, jež digitálním pasům přiznala stejnou právní platnost jako papírovým dokladům." },
  { country: "ua", year: 2020, category: "Everyday life", text: "Celostátní koronavirový lockdown na jaře uzavřel školy, kavárny i kyjevské metro, čímž se podzemní dráha v hlavním městě poprvé od svého otevření před desetiletími zcela zastavila." },
  { country: "ua", year: 2021, category: "Politics", text: "Od ledna vstoupil v platnost dlouho diskutovaný zákon nařizující ukrajinštinu jako jazyk zákaznických služeb v obchodech, restauracích a veřejné sféře, který číšníkům a pokladním ukládal oslovovat zákazníky nejprve ukrajinsky." },
  { country: "ua", year: 2021, category: "Sport", text: "Pod vedením fotbalové legendy Andrije Ševčenka postoupil národní tým poprvé do čtvrtfinále mistrovství Evropy poté, co hlavička Artema Dovbyka ve 121. minutě nastavení porazila v prodloužení Švédsko." },
  { country: "ua", year: 2021, category: "Everyday life", text: "Do jara klesl počet obyvatel na zhruba 41 milionů, což byl trvalý úbytek poháněný nízkou porodností a emigrací, jenž dlouho předcházel nadcházející válce." },
  { country: "ua", year: 2022, category: "Upheaval", text: "V časných ranních hodinách 24. února udeřily rakety na letiště a města a kolony tanků se z Běloruska valily k hlavnímu městu, čímž začala plnohodnotná invaze, kterou obránci během několika týdnů u Kyjeva odrazili." },
  { country: "ua", year: 2022, category: "Upheaval", text: "Poté co se ruské jednotky začátkem dubna stáhly z měst severně od hlavního města, byly ulice Buči nalezeny poseté těly popravených civilistů, důkazem zvěrstev, jež šokovala svět." },
  { country: "ua", year: 2022, category: "Upheaval", text: "Přístavní město Mariupol bylo obleženo a rozbombardováno na sutiny a v polovině až konci května dostali poslední obránci, zakopaní v rozlehlém ocelářském závodě Azovstal, po týdnech v podzemí rozkaz vzdát se." },
  { country: "ua", year: 2022, category: "Politics", text: "Dne 23. června udělila Evropská rada zemi oficiální status kandidáta na členství v Evropské unii, krok, o němž se dlouho soudilo, že je vzdálen desítky let." },
  { country: "ua", year: 2022, category: "Everyday life", text: "Dohoda zprostředkovaná OSN a Tureckem a podepsaná v červenci v Istanbulu znovu otevřela černomořské přístavy, aby miliony tun obilí uvízlého v Oděse mohly opět zamířit na světové trhy." },
  { country: "ua", year: 2022, category: "Culture", text: "Folkrapová skupina Kalush Orchestra vyhrála v květnu Eurovizi v Turíně s písní „Stefania“, kterou její frontman napsal pro svou matku a jež nabyla nového významu jako válečná hymna." },
  { country: "ua", year: 2022, category: "Everyday life", text: "Od října uvrhly vlny raketových a dronových úderů na elektrárny města do rotujících výpadků proudu a domácnosti se naučily žít s generátory, svíčkami a hučením nabíjecích stanic po celou mrazivou zimu." },
  { country: "ua", year: 2023, category: "Upheaval", text: "V časných ranních hodinách 6. června se protrhla mohutná Kachovská přehrada na Dněpru, čímž rozpoutala katastrofální povodně níže po proudu napříč Chersonskou oblastí a vypustila nádrž, jež napájela pole a chladicí nádrže." },
  { country: "ua", year: 2023, category: "Upheaval", text: "Dlouho očekávaná letní protiofenziva se pomalu prokousávala hustými ruskými minovými poli a zákopy a do listopadu vrchní velitel veřejně popsal frontu jako patovou." },
  { country: "ua", year: 2023, category: "Culture", text: "Drásavý dokument Mstyslava Černova „20 dní v Mariupolu“, natočený novináři agentury Associated Press uvězněnými v obleženém městě, byl vybrán jako oscarová přihláška země." },
  { country: "ua", year: 2024, category: "Sport", text: "V květnu v Rijádu porazil boxer Oleksandr Usyk na body Tysona Furyho a stal se prvním nezpochybnitelným mistrem světa v těžké váze éry čtyř pásů, prvním mužem, který tuto váhu sjednotil po 24 letech." },
  { country: "ua", year: 2024, category: "Upheaval", text: "Dne 6. srpna pronikly jednotky přes hranici do ruské Kurské oblasti, šlo o první cizí obsazení ruské půdy od druhé světové války, a obsadily desítky sídel, než se linie ustálila." },
  { country: "ua", year: 2024, category: "Culture", text: "Na Eurovizi v Malmö skončilo duo alyona alyona a Jerry Heil třetí s písní „Teresa & Maria“, skladbou o odolnosti spojující rap a vzletný zpěv." },
  { country: "ua", year: 2024, category: "Culture", text: "Dokument „20 dní v Mariupolu“ získal Oscara za nejlepší dokumentární film, vůbec první Oscar v dějinách země, přičemž režisér Mstyslav Černov řekl, že by si přál, aby ho nikdy nemusel natočit." },
  { country: "ua", year: 2025, category: "Politics", text: "Únorová schůzka v Oválné pracovně, jež měla zpečetit dohodu o nerostných surovinách, se zvrhla v nevídanou televizní přestřelku slov, přestože přepracovaná dohoda vytvářející společný fond obnovy byla nakonec koncem dubna podepsána." },
  { country: "ua", year: 2025, category: "Science & tech", text: "Dne 1. června vypustila odvážná operace s krycím názvem Pavučina 117 malých dronů z nákladních aut hluboko uvnitř Ruska, jež udeřily na základny strategických bombardérů a zničily či poškodily desítky letadel v hodnotě miliard." },
  { country: "ua", year: 2025, category: "Politics", text: "V Istanbulu se poprvé od roku 2022 obnovila přímá jednání, a ačkoli z nich nevzešlo žádné příměří, jejich kola přinesla rozsáhlé výměny vězňů, kdy každá strana vrátila nejméně tisíc zajatců." },
  { country: "ua", year: 2025, category: "Everyday life", text: "Čtvrtá válečná zima zastihla rodiny, jak si opět hromadí powerbanky a přenosné vařiče, neboť opakované údery na rozvodnou síť si vynutily plánované výpadky proudu napříč městy země." },
];
